// Forward declarations for diff viewer
struct DiffLineWidget;
struct DiffLinePool;
struct DiffViewerWidget;

// External text format for monospace code display
extern IDWriteTextFormat* g_text_format_mono;
extern IDWriteTextFormat* g_text_format_path;

// Index entry pointing to a single diff line with precomputed position
struct DiffLineEntry {
    DiffLine* line;           // Pointer into FileDiff full_diff_lines
    float y_offset;           // Absolute Y position from content top
    // hunk_index is uint32 to handle pathological diffs (auto-generated files
    // with thousands of alternating added/removed blocks). UINT32_MAX = context.
    uint32_t hunk_index;
    uint32_t line_in_file;    // Index within full file
};

// Flat index for O(1) visible range calculation
struct DiffLineIndex {
    DiffLineEntry* entries = nullptr;   // Flat array (allocated from arena)
    size_t count = 0;                   // Total line count
    size_t capacity = 0;                // Allocated capacity
    float total_height = 0.0f;          // Total content height
    float line_height = 0.0f;           // Fixed height per line

    // Hunk positions for navigation (first changed line index in each hunk)
    size_t* hunk_first_change = nullptr; // Index into entries for first change in each hunk
    size_t hunk_region_count = 0;        // Number of hunk regions (groups of changes)

    void build_from_diff(const FileDiff* diff, float lh) {
        line_height = lh;

        // Use full_diff_lines for complete file view
        size_t total = diff ? diff->full_diff_line_count : 0;

        // Ensure capacity
        if (total > capacity) {
            void* mem = malloc(total * sizeof(DiffLineEntry));
            if (!mem) {
                count = 0;
                total_height = 0.0f;
                return;
            }
            if (entries) free(entries);
            entries = static_cast<DiffLineEntry*>(mem);
            capacity = total;
        }

        // Free old hunk positions
        if (hunk_first_change) {
            free(hunk_first_change);
            hunk_first_change = nullptr;
        }
        hunk_region_count = 0;

        // Build flat index from full_diff_lines
        count = 0;
        float y = 0.0f;

        if (diff && diff->full_diff_lines) {
            // First pass: build entries and count hunk regions
            // A hunk region is a group of consecutive changed lines (with context gap tolerance)
            const int CONTEXT_GAP = DiffViewer::CONTEXT_LINES * 2 + 1;  // Gap to start new region
            int last_change_idx = -CONTEXT_GAP - 1;
            size_t temp_hunk_count = 0;

            for (size_t i = 0; i < diff->full_diff_line_count; i++) {
                DiffLine* line = &diff->full_diff_lines[i];

                entries[count].line = line;
                entries[count].y_offset = y;
                entries[count].line_in_file = static_cast<uint32_t>(i);

                // Determine hunk region for changed lines
                bool is_change = (line->type == DiffLineType::Added ||
                                  line->type == DiffLineType::Removed);
                if (is_change) {
                    // Check if this starts a new hunk region
                    if ((int)i - last_change_idx > CONTEXT_GAP) {
                        temp_hunk_count++;
                    }
                    entries[count].hunk_index = static_cast<uint32_t>(temp_hunk_count > 0 ? temp_hunk_count - 1 : 0);
                    last_change_idx = (int)i;
                } else {
                    // Context lines don't belong to a specific hunk
                    entries[count].hunk_index = UINT32_MAX;
                }

                count++;
                y += line_height;
            }

            hunk_region_count = temp_hunk_count;

            // Second pass: build hunk_first_change array
            if (hunk_region_count > 0) {
                hunk_first_change = static_cast<size_t*>(malloc(hunk_region_count * sizeof(size_t)));
                if (hunk_first_change) {
                    size_t current_hunk = SIZE_MAX;
                    for (size_t i = 0; i < count; i++) {
                        if (entries[i].hunk_index != UINT32_MAX &&
                            entries[i].hunk_index != current_hunk) {
                            current_hunk = entries[i].hunk_index;
                            if (current_hunk < hunk_region_count) {
                                hunk_first_change[current_hunk] = i;
                            }
                        }
                    }
                }
            }
        }

        total_height = y;
    }

    void clear() {
        count = 0;
        total_height = 0.0f;
        hunk_region_count = 0;
    }

    void destroy() {
        if (entries) {
            free(entries);
            entries = nullptr;
        }
        if (hunk_first_change) {
            free(hunk_first_change);
            hunk_first_change = nullptr;
        }
        capacity = 0;
        count = 0;
        total_height = 0.0f;
        hunk_region_count = 0;
    }

    // O(1) direct calculation since all lines are fixed height
    size_t first_visible_index(float scroll_y) const {
        if (count == 0 || line_height <= 0) return 0;
        int64_t idx = static_cast<int64_t>(scroll_y / line_height);
        if (idx < 0) return 0;
        if (static_cast<size_t>(idx) >= count) return count > 0 ? count - 1 : 0;
        return static_cast<size_t>(idx);
    }

    // Calculate how many lines fit in viewport
    size_t lines_in_viewport(float viewport_height) const {
        if (line_height <= 0) return 0;
        return static_cast<size_t>(viewport_height / line_height) + 2;  // +2 for partial lines
    }
};

// Individual diff line widget with aggressive text layout caching
struct DiffLineWidget : Widget {
    // Data binding (set when recycled from pool)
    const DiffLine* line = nullptr;
    int pool_index = -1;              // Index in pool for release

    // Side-by-side mode: which pane this widget is rendering for
    DiffPaneSide pane_side = DiffPaneSide::Full;
    bool is_placeholder = false;      // True if this is a placeholder row (no line data)

    // Content-relative Y position for stripe alignment (doesn't change with scroll)
    float content_y_offset = 0.0f;

    // Cached text layouts (released on unbind)
    IDWriteTextLayout* layout_old_num = nullptr;
    IDWriteTextLayout* layout_new_num = nullptr;
    IDWriteTextLayout* layout_content = nullptr;

    // Cache invalidation tracking
    float cached_content_width = 0.0f;
    bool cache_valid = false;

    // Actual rendered text width (for horizontal scrolling)
    float actual_content_width = 0.0f;

    // Horizontal scroll offset (set by DiffViewerWidget before rendering)
    float scroll_x_offset = 0.0f;

    // Wide string buffers for text conversion
    wchar_t content_wide[4096];
    wchar_t old_num_str[16];
    wchar_t new_num_str[16];

    DiffLineWidget() : Widget() {
        debug_name = "DiffLineWidget";
        content_wide[0] = L'\0';
        old_num_str[0] = L'\0';
        new_num_str[0] = L'\0';
    }

    // Bind to a diff line (called when recycling from pool) - inline mode
    void bind(const DiffLine* l, int idx) {
        bind_for_pane(l, idx, DiffPaneSide::Full, false);
    }

    // Bind for side-by-side mode with pane specification
    void bind_for_pane(const DiffLine* l, int idx, DiffPaneSide side, bool placeholder) {
        line = l;
        pool_index = idx;
        pane_side = side;
        is_placeholder = placeholder;
        cache_valid = false;  // Invalidate cache when binding new data

        // Pre-convert line numbers to wide strings
        if (line && !is_placeholder) {
            // In side-by-side mode, only show relevant line number
            if (pane_side == DiffPaneSide::Left) {
                // Left pane: show old line number
                if (line->old_line_num >= 0) {
                    swprintf_s(old_num_str, L"%d", line->old_line_num);
                } else {
                    old_num_str[0] = L'\0';
                }
                new_num_str[0] = L'\0';  // Don't show new line num in left pane
            } else if (pane_side == DiffPaneSide::Right) {
                // Right pane: show new line number
                if (line->new_line_num >= 0) {
                    swprintf_s(new_num_str, L"%d", line->new_line_num);
                } else {
                    new_num_str[0] = L'\0';
                }
                old_num_str[0] = L'\0';  // Don't show old line num in right pane
            } else {
                // Full mode (inline): show both
                if (line->old_line_num >= 0) {
                    swprintf_s(old_num_str, L"%d", line->old_line_num);
                } else {
                    old_num_str[0] = L'\0';
                }
                if (line->new_line_num >= 0) {
                    swprintf_s(new_num_str, L"%d", line->new_line_num);
                } else {
                    new_num_str[0] = L'\0';
                }
            }

            // Convert content to wide string
            if (line->content) {
                int result = MultiByteToWideChar(CP_UTF8, 0, line->content, -1, content_wide, 4096);
                if (result == 0) content_wide[0] = L'\0';
            } else {
                content_wide[0] = L'\0';
            }
        } else {
            old_num_str[0] = L'\0';
            new_num_str[0] = L'\0';
            content_wide[0] = L'\0';
        }
    }

    // Unbind and release cached layouts
    // Note: pool_index is NOT reset - it's the widget's permanent identity in the pool
    void unbind() {
        line = nullptr;
        pane_side = DiffPaneSide::Full;
        is_placeholder = false;

        if (layout_old_num) {
            layout_old_num->Release();
            layout_old_num = nullptr;
        }
        if (layout_new_num) {
            layout_new_num->Release();
            layout_new_num = nullptr;
        }
        if (layout_content) {
            layout_content->Release();
            layout_content = nullptr;
        }

        cache_valid = false;
        cached_content_width = 0.0f;
    }

    // Create text layouts if needed (lazy creation)
    void ensure_layouts(float content_width) {
        if (!line && !is_placeholder) return;
        if (is_placeholder) {
            // Placeholders don't need text layouts
            cache_valid = true;
            actual_content_width = 0.0f;
            return;
        }

        // Check if we need to recreate due to width change
        constexpr float WIDTH_EPSILON = 1.0f;
        bool width_changed = (cached_content_width - content_width > WIDTH_EPSILON) ||
                            (content_width - cached_content_width > WIDTH_EPSILON);

        if (cache_valid && !width_changed) return;

        // Release old layouts
        if (layout_old_num) { layout_old_num->Release(); layout_old_num = nullptr; }
        if (layout_new_num) { layout_new_num->Release(); layout_new_num = nullptr; }
        if (layout_content) { layout_content->Release(); layout_content = nullptr; }

        // Create line number layouts (right-aligned)
        if (g_dwrite_factory && g_text_format_mono) {
            // In side-by-side mode, only create the relevant line number layout
            if (old_num_str[0] && (pane_side == DiffPaneSide::Full || pane_side == DiffPaneSide::Left)) {
                g_dwrite_factory->CreateTextLayout(
                    old_num_str, static_cast<UINT32>(wcslen(old_num_str)),
                    g_text_format_mono, DiffViewer::LINE_NUMBER_WIDTH - 8.0f,
                    DiffViewer::LINE_HEIGHT, &layout_old_num);
                if (layout_old_num) {
                    layout_old_num->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_TRAILING);
                }
            }

            if (new_num_str[0] && (pane_side == DiffPaneSide::Full || pane_side == DiffPaneSide::Right)) {
                g_dwrite_factory->CreateTextLayout(
                    new_num_str, static_cast<UINT32>(wcslen(new_num_str)),
                    g_text_format_mono, DiffViewer::LINE_NUMBER_WIDTH - 8.0f,
                    DiffViewer::LINE_HEIGHT, &layout_new_num);
                if (layout_new_num) {
                    layout_new_num->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_TRAILING);
                }
            }

            // Create content layout with no wrapping
            if (content_wide[0]) {
                // Use large max width to prevent wrapping, then measure actual width
                g_dwrite_factory->CreateTextLayout(
                    content_wide, static_cast<UINT32>(wcslen(content_wide)),
                    g_text_format_mono, 100000.0f,  // Large max width
                    DiffViewer::LINE_HEIGHT, &layout_content);

                if (layout_content) {
                    // Disable word wrapping
                    layout_content->SetWordWrapping(DWRITE_WORD_WRAPPING_NO_WRAP);

                    // Query actual text width for horizontal scrolling
                    DWRITE_TEXT_METRICS metrics;
                    if (SUCCEEDED(layout_content->GetMetrics(&metrics))) {
                        actual_content_width = metrics.width;
                    }
                }
            } else {
                actual_content_width = 0.0f;
            }
        }

        cached_content_width = content_width;
        cache_valid = true;
    }

    // Render diagonal stripe pattern for placeholder rows
    void render_placeholder(RenderContext& ctx) {
        float x = rect.x;
        float y = rect.y;
        float w = rect.width;
        float h = rect.height;

        // Fill base background
        D2D1_RECT_F bg_rect = D2D1::RectF(x, y, x + w, y + h);
        ctx.fill_rect(bg_rect, DiffViewer::PLACEHOLDER_BG);

        // Draw diagonal stripes
        constexpr float STRIPE_W = DiffViewer::PLACEHOLDER_STRIPE_WIDTH;
        constexpr float STRIPE_SPACING = DiffViewer::PLACEHOLDER_STRIPE_SPACING;

        // Clip to widget bounds
        ctx.target->PushAxisAlignedClip(bg_rect, D2D1_ANTIALIAS_MODE_PER_PRIMITIVE);

        // Draw diagonal lines from top-left to bottom-right
        // For continuous stripes across rows, adjust offset based on y position
        // so that stripes align: for 45-degree lines, points where (x - y) = const are on same line
        ctx.brush->SetColor(color_from_argb(DiffViewer::PLACEHOLDER_STRIPE));

        // Calculate starting offset to align with other rows
        // Use content_y_offset (content-relative) instead of screen y for consistent alignment
        // across virtualized widgets that get repositioned during scroll
        float y_phase = fmodf(content_y_offset, STRIPE_SPACING);

        // For 45-degree down-right stripes: as content_y increases, shift pattern RIGHT
        // (the stripe at y=0,x=0 continues to y=20,x=20, so next row needs +20 offset)
        // Extend lines slightly beyond row bounds to eliminate anti-aliasing gaps between rows
        constexpr float OVERLAP = 1.0f;
        for (float offset = -h - STRIPE_SPACING + y_phase - OVERLAP; offset < w + h + OVERLAP; offset += STRIPE_SPACING) {
            D2D1_POINT_2F p1 = D2D1::Point2F(x + offset, y - OVERLAP);
            D2D1_POINT_2F p2 = D2D1::Point2F(x + offset + h + 2*OVERLAP, y + h + OVERLAP);
            ctx.target->DrawLine(p1, p2, ctx.brush, STRIPE_W * 0.5f);
        }

        ctx.target->PopAxisAlignedClip();
    }

    void render(RenderContext& ctx) override {
        if (!(flags & WidgetFlags::Visible)) return;

        // Handle placeholder rendering
        if (is_placeholder) {
            render_placeholder(ctx);
            return;
        }

        if (!line) return;

        // Layout constants - different for inline vs side-by-side
        constexpr float LINE_NUM_WIDTH = DiffViewer::LINE_NUMBER_WIDTH;
        constexpr float BORDER_WIDTH = DiffViewer::LEFT_BORDER_WIDTH;
        constexpr float CONTENT_PAD = DiffViewer::CONTENT_PADDING;
        constexpr float CENTER_GUTTER_WIDTH = DiffViewer::CENTER_GUTTER_WIDTH;

        // Gutter width depends on mode
        // In inline mode, includes space for center gutter after line numbers
        float gutter_width;
        if (pane_side == DiffPaneSide::Full) {
            gutter_width = DiffViewer::GUTTER_WIDTH + CENTER_GUTTER_WIDTH;  // Two columns (90px) + center gutter (30px)
        } else {
            gutter_width = LINE_NUM_WIDTH;  // Single column (45px)
        }

        float x = rect.x;
        float y = rect.y;
        float w = rect.width;
        float h = rect.height;

        // Determine colors based on line type
        uint32_t bg_color = 0;
        uint32_t border_color = 0;
        uint32_t text_color = Theme::TEXT_PRIMARY;
        uint32_t highlight_color = 0;
        wchar_t prefix = L' ';
        bool show_prefix = (pane_side == DiffPaneSide::Full);  // Only show prefix in inline mode

        switch (line->type) {
            case DiffLineType::Added:
                bg_color = DiffViewer::BG_ADDED;
                border_color = Theme::STATUS_ADDED;
                text_color = Theme::TEXT_PRIMARY;
                highlight_color = DiffViewer::BG_ADDED_STRONG;
                prefix = L'+';
                break;
            case DiffLineType::Removed:
                bg_color = DiffViewer::BG_REMOVED;
                border_color = Theme::STATUS_DELETED;
                text_color = Theme::TEXT_PRIMARY;
                highlight_color = DiffViewer::BG_REMOVED_STRONG;
                prefix = L'-';
                break;
            case DiffLineType::HunkHeader:
                // Skip hunk headers in side-by-side mode
                if (pane_side != DiffPaneSide::Full) return;
                bg_color = DiffViewer::BG_HUNK;
                text_color = Theme::ACCENT;
                prefix = L'@';
                break;
            case DiffLineType::Context:
            default:
                text_color = Theme::TEXT_SECONDARY;
                prefix = L' ';
                break;
        }

        // 1. Draw background (if any)
        if (bg_color != 0) {
            D2D1_RECT_F bg_rect = D2D1::RectF(x, y, x + w, y + h);
            ctx.fill_rect(bg_rect, bg_color);
        }

        // 2. Draw left border for added/removed lines
        if (border_color != 0) {
            D2D1_RECT_F border_rect = D2D1::RectF(
                x + gutter_width, y,
                x + gutter_width + BORDER_WIDTH, y + h);
            ctx.fill_rect(border_rect, border_color);
        }

        // 3. Draw line numbers in gutter
        if (pane_side == DiffPaneSide::Full) {
            // Inline mode: two columns
            if (layout_old_num) {
                ctx.brush->SetColor(color_from_argb(Theme::TEXT_MUTED));
                D2D1_POINT_2F pt = D2D1::Point2F(x + 4.0f, y);
                ctx.target->DrawTextLayout(pt, layout_old_num, ctx.brush);
            }
            if (layout_new_num) {
                ctx.brush->SetColor(color_from_argb(Theme::TEXT_MUTED));
                D2D1_POINT_2F pt = D2D1::Point2F(x + LINE_NUM_WIDTH + 4.0f, y);
                ctx.target->DrawTextLayout(pt, layout_new_num, ctx.brush);
            }
        } else {
            // Side-by-side mode: single column at left edge
            IDWriteTextLayout* num_layout = (pane_side == DiffPaneSide::Left) ? layout_old_num : layout_new_num;
            if (num_layout) {
                ctx.brush->SetColor(color_from_argb(Theme::TEXT_MUTED));
                D2D1_POINT_2F pt = D2D1::Point2F(x + 4.0f, y);
                ctx.target->DrawTextLayout(pt, num_layout, ctx.brush);
            }
        }

        // 4. Draw gutter separator (after line numbers, before center gutter in inline mode)
        float line_num_gutter_end = (pane_side == DiffPaneSide::Full)
                                   ? (x + DiffViewer::GUTTER_WIDTH)
                                   : (x + LINE_NUM_WIDTH);
        D2D1_RECT_F gutter_sep = D2D1::RectF(
            line_num_gutter_end - 1.0f, y,
            line_num_gutter_end, y + h);
        ctx.fill_rect(gutter_sep, Theme::BORDER);

        // Content area starts after gutter + border, offset by horizontal scroll
        float content_x = x + gutter_width + BORDER_WIDTH + CONTENT_PAD - scroll_x_offset;

        // Clip content area so text doesn't overlap line numbers when scrolled
        float content_clip_left = x + gutter_width + BORDER_WIDTH;
        D2D1_RECT_F content_clip = D2D1::RectF(content_clip_left, y, x + w, y + h);
        ctx.target->PushAxisAlignedClip(content_clip, D2D1_ANTIALIAS_MODE_PER_PRIMITIVE);

        // 5. Draw prefix character (+/-/space/@) - only in inline mode
        if (show_prefix && g_text_format_mono) {
            wchar_t prefix_str[2] = { prefix, L'\0' };
            D2D1_RECT_F prefix_rect = D2D1::RectF(
                content_x - CONTENT_PAD + 2.0f, y,
                content_x, y + h);
            ctx.draw_text(prefix_str, 1, g_text_format_mono, prefix_rect, text_color);
        }

        // 6. Draw intraline highlights (before text)
        if (layout_content && line->intra_spans && line->intra_span_count > 0 && highlight_color != 0) {
            for (uint16_t i = 0; i < line->intra_span_count; i++) {
                DiffSpan* span = &line->intra_spans[i];

                // Get hit test metrics for this span
                DWRITE_HIT_TEST_METRICS* metrics = nullptr;
                UINT32 metric_count = 0;

                // First call to get count
                layout_content->HitTestTextRange(
                    span->start, span->length,
                    content_x, y,
                    nullptr, 0, &metric_count);

                if (metric_count > 0) {
                    metrics = static_cast<DWRITE_HIT_TEST_METRICS*>(
                        alloca(metric_count * sizeof(DWRITE_HIT_TEST_METRICS)));

                    layout_content->HitTestTextRange(
                        span->start, span->length,
                        content_x, y,
                        metrics, metric_count, &metric_count);

                    // Draw highlight rectangles
                    for (UINT32 m = 0; m < metric_count; m++) {
                        D2D1_RECT_F hl_rect = D2D1::RectF(
                            metrics[m].left, metrics[m].top,
                            metrics[m].left + metrics[m].width,
                            metrics[m].top + metrics[m].height);
                        ctx.fill_rect(hl_rect, highlight_color);
                    }
                }
            }
        }

        // 7. Draw content text with syntax highlighting
        if (layout_content) {
            // Draw base text in line-type color first
            ctx.brush->SetColor(color_from_argb(text_color));
            ctx.target->DrawTextLayout(D2D1::Point2F(content_x, y), layout_content, ctx.brush);

            // Overlay syntax-highlighted spans on top
            if (line->syntax_spans && line->syntax_span_count > 0) {
                for (uint16_t i = 0; i < line->syntax_span_count; i++) {
                    SyntaxSpan* span = &line->syntax_spans[i];
                    uint32_t span_color = SyntaxColors::get_token_color(static_cast<uint8_t>(span->token));

                    DWRITE_HIT_TEST_METRICS metrics[8];
                    UINT32 metric_count = 0;

                    layout_content->HitTestTextRange(
                        span->start, span->length,
                        content_x, y,
                        metrics, 8, &metric_count);

                    for (UINT32 m = 0; m < metric_count; m++) {
                        D2D1_RECT_F clip_rect = D2D1::RectF(
                            metrics[m].left, metrics[m].top,
                            metrics[m].left + metrics[m].width,
                            metrics[m].top + metrics[m].height);

                        ctx.target->PushAxisAlignedClip(clip_rect, D2D1_ANTIALIAS_MODE_PER_PRIMITIVE);
                        ctx.brush->SetColor(color_from_argb(span_color));
                        ctx.target->DrawTextLayout(D2D1::Point2F(content_x, y), layout_content, ctx.brush);
                        ctx.target->PopAxisAlignedClip();
                    }
                }
            }
        }

        // Pop content clip
        ctx.target->PopAxisAlignedClip();
    }
};

// Pool manager for recycling DiffLineWidget instances
// Uses free list for O(1) acquire/release instead of O(n) scan
struct DiffLinePool {
    static constexpr size_t POOL_SIZE = 200;  // Enough for viewport + overscan
    static constexpr int FREE_LIST_END = -1;

    DiffLineWidget* widgets[POOL_SIZE] = {};  // Pre-allocated in arena
    int next_free[POOL_SIZE] = {};            // Free list links (-1 = end, -2 = in use)
    int free_head = FREE_LIST_END;            // Head of free list
    size_t allocated_count = 0;               // How many have been created
    size_t in_use_count = 0;                  // How many are currently bound

    // Initialize pool by pre-allocating all widgets
    void init(WidgetArena& arena) {
        free_head = FREE_LIST_END;
        for (size_t i = 0; i < POOL_SIZE; i++) {
            widgets[i] = arena.create<DiffLineWidget>();
            if (widgets[i]) {
                widgets[i]->pool_index = static_cast<int>(i);
                // Build free list in reverse order so index 0 is acquired first
                next_free[i] = free_head;
                free_head = static_cast<int>(i);
                allocated_count++;
            }
        }
    }

    // Acquire an unused widget from the pool - O(1)
    DiffLineWidget* acquire() {
        if (free_head == FREE_LIST_END) return nullptr;  // Pool exhausted

        int idx = free_head;
        free_head = next_free[idx];
        next_free[idx] = -2;  // Mark as in use
        in_use_count++;
        return widgets[idx];
    }

    // Release a widget back to the pool - O(1)
    void release(DiffLineWidget* w) {
        if (!w || w->pool_index < 0 || static_cast<size_t>(w->pool_index) >= POOL_SIZE) return;

        int idx = w->pool_index;
        if (widgets[idx] == w && next_free[idx] == -2) {  // Currently in use
            w->unbind();
            next_free[idx] = free_head;
            free_head = idx;
            in_use_count--;
        }
    }

    // Release all widgets (for diff change)
    void release_all() {
        free_head = FREE_LIST_END;
        for (size_t i = 0; i < allocated_count; i++) {
            if (next_free[i] == -2 && widgets[i]) {  // Was in use
                widgets[i]->unbind();
            }
            // Rebuild free list
            next_free[i] = free_head;
            free_head = static_cast<int>(i);
        }
        in_use_count = 0;
    }

    // Count of currently in-use widgets - O(1)
    size_t active_count() const {
        return in_use_count;
    }
};

// ============================================================================
// DiffGutterWidget - Center gutter between left/right panes in side-by-side mode
// ============================================================================
//
// 30px wide vertical bar with:
// - Shadow edges for inset appearance (2px on each side)
// - Gradient band change indicators (red/green/split)
// - Drag-to-resize at shadow edges (200px minimum pane width)
// ============================================================================

struct DiffGutterWidget : Widget {
    // Reference to indices for drawing change indicators
    const SideBySideLineIndex* sbs_index = nullptr;  // For side-by-side mode
    const DiffLineIndex* line_index = nullptr;       // For inline mode
    bool use_inline_mode = false;                    // Which index to use

    // Scroll state (from parent DiffViewerWidget)
    float scroll_y = 0.0f;
    float viewport_height = 0.0f;

    // Drag state for resizing
    bool is_dragging = false;
    bool is_hover_left_edge = false;
    bool is_hover_right_edge = false;
    float drag_start_x = 0.0f;
    float drag_start_ratio = 0.5f;

    // Split ratio (0.0-1.0, 0.5 = centered)
    float* split_ratio = nullptr;  // Pointer to parent's split_ratio

    // Callback for when split ratio changes
    void (*on_split_changed)(float new_ratio, void* user_data) = nullptr;
    void* split_changed_user_data = nullptr;

    // Layout constants
    static constexpr float GUTTER_WIDTH = DiffViewer::CENTER_GUTTER_WIDTH;
    static constexpr float SHADOW_WIDTH = DiffViewer::GUTTER_SHADOW_WIDTH;
    static constexpr float DRAG_ZONE_WIDTH = 6.0f;  // Wider than shadow for easier grabbing

    DiffGutterWidget() : Widget() {
        debug_name = "DiffGutterWidget";
        width_mode = SizeMode::Fixed;
        preferred_width = GUTTER_WIDTH;
        height_mode = SizeMode::Fill;
    }

    void set_sbs_index(const SideBySideLineIndex* index) {
        sbs_index = index;
        set_dirty();
    }

    void set_line_index(const DiffLineIndex* index) {
        line_index = index;
        set_dirty();
    }

    void set_mode(bool inline_mode) {
        use_inline_mode = inline_mode;
        set_dirty();
    }

    void set_split_ratio_ptr(float* ratio) {
        split_ratio = ratio;
    }

    void update_scroll(float sy, float vh) {
        if (scroll_y != sy || viewport_height != vh) {
            scroll_y = sy;
            viewport_height = vh;
            set_dirty();
        }
    }

    // Check if point is in left drag zone
    bool is_in_left_drag_zone(float local_x) const {
        return local_x >= 0 && local_x < DRAG_ZONE_WIDTH;
    }

    // Check if point is in right drag zone
    bool is_in_right_drag_zone(float local_x) const {
        return local_x > (GUTTER_WIDTH - DRAG_ZONE_WIDTH) && local_x <= GUTTER_WIDTH;
    }

    void render(RenderContext& ctx) override {
        if (!(flags & WidgetFlags::Visible)) return;

        float x = rect.x;
        float y = rect.y;
        float w = rect.width;
        float h = rect.height;

        // 1. Fill gutter background (same as diff viewer)
        D2D1_RECT_F bg_rect = D2D1::RectF(x, y, x + w, y + h);
        ctx.fill_rect(bg_rect, DiffViewer::GUTTER_BG);

        // 2. Draw inset shadow edges (dark gradient from edges inward)
        auto draw_edge_shadow = [&](float start_x, int direction) {
            for (int i = 0; i < 4; i++) {
                float alpha = 0.5f * (1.0f - (float)i / 4.0f);  // 50% to 0%
                uint32_t shadow_color = (uint32_t)(alpha * 255) << 24;  // Black with varying alpha
                float px = start_x + direction * (float)i;
                D2D1_RECT_F shadow_rect = D2D1::RectF(px, y, px + 1.0f, y + h);
                ctx.fill_rect(shadow_rect, shadow_color);
            }
        };
        draw_edge_shadow(x, 1);              // Left shadow: fading inward
        draw_edge_shadow(x + w - 1.0f, -1);  // Right shadow: fading inward

        // 3. Draw change indicators if we have side-by-side data
        if (sbs_index && sbs_index->pair_count > 0 && viewport_height > 0) {
            render_change_indicators(ctx);
        }

        // 4. Draw hover highlights on drag zones
        if (is_hover_left_edge || is_dragging) {
            D2D1_RECT_F hover_rect = D2D1::RectF(x, y, x + DRAG_ZONE_WIDTH, y + h);
            ctx.fill_rect(hover_rect, 0x40FFFFFF);  // More visible white highlight
        }
        if (is_hover_right_edge || is_dragging) {
            D2D1_RECT_F hover_rect = D2D1::RectF(x + w - DRAG_ZONE_WIDTH, y, x + w, y + h);
            ctx.fill_rect(hover_rect, 0x40FFFFFF);
        }
    }

    void render_change_indicators(RenderContext& ctx) {
        // Thin centered line indicator
        constexpr float LINE_WIDTH = 2.0f;
        float line_x = rect.x + (rect.width - LINE_WIDTH) / 2.0f;
        constexpr uint32_t LINE_COLOR = 0x60808080;  // Subtle gray

        // Visible bounds (gutter rect.y is already at content top, no header offset needed)
        float content_top = rect.y;
        float content_bottom = rect.y + rect.height;

        // Track current change section for merging
        bool in_section = false;
        float section_start_y = 0.0f;  // Content-relative Y
        float section_end_y = 0.0f;    // Content-relative Y (bottom of last line)

        // Lambda to render a completed section as a thin gray line
        auto flush_section = [&]() {
            if (!in_section) return;

            // Convert to screen coordinates
            // y_offsets are relative to content start (HEADER_HEIGHT below widget top)
            // but gutter rect.y is at viewport_top, so add HEADER_HEIGHT for position
            float content_to_screen = -scroll_y + rect.y + DiffViewer::HEADER_HEIGHT;
            float screen_start = section_start_y + content_to_screen;
            float screen_end = section_end_y + content_to_screen;

            // Skip if entirely outside visible area
            if (screen_end <= content_top || screen_start >= content_bottom) {
                in_section = false;
                return;
            }

            // Clamp to visible bounds
            if (screen_start < content_top) screen_start = content_top;
            if (screen_end > content_bottom) screen_end = content_bottom;

            // Render thin centered gray line
            D2D1_RECT_F line_rect = D2D1::RectF(line_x, screen_start, line_x + LINE_WIDTH, screen_end);
            ctx.fill_rect(line_rect, LINE_COLOR);

            in_section = false;
        };

        if (use_inline_mode) {
            // Inline mode: use line_index which includes hunk headers
            if (!line_index || line_index->count == 0) return;
            float line_height = line_index->line_height;

            for (size_t i = 0; i < line_index->count; i++) {
                const DiffLineEntry& entry = line_index->entries[i];
                if (!entry.line) continue;

                DiffLineType type = entry.line->type;

                // Context and HunkHeader lines end the current section
                if (type == DiffLineType::Context || type == DiffLineType::HunkHeader) {
                    flush_section();
                } else {
                    // Added or Removed line - part of a change section
                    if (!in_section) {
                        in_section = true;
                        section_start_y = entry.y_offset;
                    }
                    section_end_y = entry.y_offset + line_height;
                }
            }
        } else {
            // Side-by-side mode: use sbs_index which skips hunk headers
            if (!sbs_index || sbs_index->pair_count == 0) return;
            float line_height = sbs_index->line_height;

            for (size_t i = 0; i < sbs_index->pair_count; i++) {
                const SideBySidePair& pair = sbs_index->pairs[i];

                if (pair.row_type == SideBySideRowType::Context) {
                    flush_section();
                } else {
                    if (!in_section) {
                        in_section = true;
                        section_start_y = pair.y_offset;
                    }
                    section_end_y = pair.y_offset + line_height;
                }
            }
        }

        // Flush any remaining section at end
        flush_section();
    }

    bool on_mouse_move(float x, float y) override {
        (void)y;

        bool was_hover_left = is_hover_left_edge;
        bool was_hover_right = is_hover_right_edge;

        is_hover_left_edge = is_in_left_drag_zone(x);
        is_hover_right_edge = is_in_right_drag_zone(x);

        // Update cursor only on transition (LoadCursor is a system call).
        // SetCursor itself is cheap, so we still call it when hovering the
        // drag zone so the OS doesn't reset to the default arrow.
        bool over_drag = is_hover_left_edge || is_hover_right_edge || is_dragging;
        if (over_drag) {
            static HCURSOR s_sizewe = LoadCursor(nullptr, IDC_SIZEWE);
            SetCursor(s_sizewe);
        }

        if (was_hover_left != is_hover_left_edge || was_hover_right != is_hover_right_edge) {
            set_dirty();
        }

        // Handle dragging
        if (is_dragging && split_ratio) {
            // During drag, x is ABSOLUTE (passed by DiffViewerWidget when is_dragging)
            // This matches how EventDispatcher passes absolute coords to captured widgets
            float abs_x = x;  // x is already absolute during drag

            // Get parent width (DiffViewerWidget)
            Widget* p = parent;
            float parent_width = p ? p->rect.width : 1000.0f;

            // Calculate available space for panes (exclude gutter width)
            float available_for_panes = parent_width - GUTTER_WIDTH;
            if (available_for_panes <= 0) return true;

            // Calculate delta from stored absolute drag start position
            float delta = abs_x - drag_start_x;

            // Calculate new left pane width based on starting ratio + delta
            float new_left_pane_width = available_for_panes * drag_start_ratio + delta;

            // Calculate new ratio (0.0-1.0)
            float new_ratio = new_left_pane_width / available_for_panes;

            // Clamp to ensure minimum pane widths (200px each side)
            float min_ratio = DiffViewer::PANE_MIN_WIDTH / available_for_panes;
            float max_ratio = 1.0f - min_ratio;

            if (new_ratio < min_ratio) new_ratio = min_ratio;
            if (new_ratio > max_ratio) new_ratio = max_ratio;

            if (*split_ratio != new_ratio) {
                *split_ratio = new_ratio;
                if (on_split_changed) {
                    on_split_changed(new_ratio, split_changed_user_data);
                }
                set_dirty();
            }

            return true;  // Consume event
        }

        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)y;

        if (button != 0) return false;

        if (is_in_left_drag_zone(x) || is_in_right_drag_zone(x)) {
            is_dragging = true;
            // Store ABSOLUTE X at drag start (x is gutter-local here, convert to absolute)
            // This matches the DragHandle pattern in sidebar
            drag_start_x = rect.x + x;
            if (split_ratio) {
                drag_start_ratio = *split_ratio;
            }
            SetCursor(LoadCursor(nullptr, IDC_SIZEWE));
            set_dirty();
            return true;  // Consume event
        }

        return false;
    }

    bool on_mouse_up(float x, float y, int button) override {
        (void)x; (void)y;

        if (button != 0) return false;

        if (is_dragging) {
            is_dragging = false;
            set_dirty();
            return true;
        }

        return false;
    }

    bool on_mouse_leave() override {
        is_hover_left_edge = false;
        is_hover_right_edge = false;
        set_dirty();
        return false;
    }
};

// Static scroll position cache (shared across diff viewer instances)
// Stored outside struct to avoid large embedded arrays causing stack issues
namespace DiffScrollCache {
    static constexpr size_t CACHE_SIZE = 32;
    struct Entry {
        char path[Git::MAX_PATH_LEN];
        float scroll_pos;
        bool used;
    };
    static Entry entries[CACHE_SIZE] = {};

    static void save(const char* path, float pos) {
        if (!path || path[0] == '\0') return;

        // Find existing entry or use empty slot
        size_t target_slot = CACHE_SIZE;
        for (size_t i = 0; i < CACHE_SIZE; i++) {
            if (entries[i].used && strcmp(entries[i].path, path) == 0) {
                target_slot = i;
                break;
            }
            if (!entries[i].used && target_slot == CACHE_SIZE) {
                target_slot = i;
            }
        }

        // If no slot found, overwrite first slot (simple eviction)
        if (target_slot == CACHE_SIZE) {
            target_slot = 0;
        }

        strcpy_s(entries[target_slot].path, path);
        entries[target_slot].scroll_pos = pos;
        entries[target_slot].used = true;
    }

    static bool get(const char* path, float* out_pos) {
        if (!path || !out_pos) return false;
        for (size_t i = 0; i < CACHE_SIZE; i++) {
            if (entries[i].used && strcmp(entries[i].path, path) == 0) {
                *out_pos = entries[i].scroll_pos;
                return true;
            }
        }
        return false;
    }
}

// Forward declaration
struct DiffViewerWidget;

// ============================================================================
// DiffHeaderWidget - Header bar with nav buttons (outside scroll area)
// ============================================================================

struct DiffHeaderWidget : Widget {
    // Reference to content widget for navigation
    DiffViewerWidget* content = nullptr;

    // Header text cache
    wchar_t header_path[Git::MAX_PATH_LEN] = {};
    int additions = 0;
    int deletions = 0;

    // Hunk navigation state (mirrors content widget state)
    size_t current_hunk = 0;
    size_t hunk_count = 0;

    // View mode toggle state
    DiffViewMode view_mode = DiffViewMode::SideBySide;
    bool toggle_hovered = false;
    bool toggle_pressed = false;

    // Button state
    bool nav_prev_hovered = false;
    bool nav_next_hovered = false;
    bool nav_prev_pressed = false;
    bool nav_next_pressed = false;

    // Layout constants
    static constexpr float HEADER_HEIGHT = DiffViewer::HEADER_HEIGHT;
    static constexpr float NAV_BUTTON_SIZE = 20.0f;
    static constexpr float NAV_COUNTER_WIDTH = 40.0f;
    static constexpr float NAV_GAP = 4.0f;
    static constexpr float NAV_TOTAL_WIDTH = NAV_BUTTON_SIZE * 2 + NAV_COUNTER_WIDTH + NAV_GAP * 2;
    static constexpr float TOGGLE_BUTTON_SIZE = 22.0f;
    static constexpr float TOGGLE_BUTTON_MARGIN = 8.0f;

    DiffHeaderWidget() : Widget() {
        debug_name = "DiffHeaderWidget";
        height_mode = SizeMode::Fixed;
        preferred_height = HEADER_HEIGHT;
        width_mode = SizeMode::Fill;
    }

    void set_content(DiffViewerWidget* c) { content = c; }

    // Set view mode (called by content widget)
    void set_view_mode(DiffViewMode mode) {
        if (view_mode != mode) {
            view_mode = mode;
            set_dirty();
        }
    }

    // Toggle button rect (far right, after stats)
    D2D1_RECT_F get_toggle_rect() const {
        float btn_x = rect.x + rect.width - TOGGLE_BUTTON_SIZE - TOGGLE_BUTTON_MARGIN;
        float btn_y = rect.y + (HEADER_HEIGHT - TOGGLE_BUTTON_SIZE) / 2.0f;
        return D2D1::RectF(btn_x, btn_y, btn_x + TOGGLE_BUTTON_SIZE, btn_y + TOGGLE_BUTTON_SIZE);
    }

    // Draw the view mode toggle icon
    void draw_toggle_icon(RenderContext& ctx, const D2D1_RECT_F& r, bool is_side_by_side, uint32_t color) {
        ctx.brush->SetColor(color_from_argb(color));
        float cx = (r.left + r.right) / 2.0f;
        float cy = (r.top + r.bottom) / 2.0f;
        constexpr float stroke = 1.5f;

        if (is_side_by_side) {
            // Side-by-side icon: two vertical columns with a divider
            // Left column
            ctx.target->DrawRectangle(D2D1::RectF(cx - 8.0f, cy - 5.0f, cx - 2.0f, cy + 5.0f), ctx.brush, stroke);
            // Right column
            ctx.target->DrawRectangle(D2D1::RectF(cx + 2.0f, cy - 5.0f, cx + 8.0f, cy + 5.0f), ctx.brush, stroke);
        } else {
            // Inline icon: three horizontal bars
            float bar_w = 12.0f;
            float bar_h = 2.0f;
            float x_start = cx - bar_w / 2.0f;
            ctx.fill_rect(D2D1::RectF(x_start, cy - 5.0f, x_start + bar_w, cy - 5.0f + bar_h), color);
            ctx.fill_rect(D2D1::RectF(x_start, cy - bar_h / 2.0f, x_start + bar_w, cy + bar_h / 2.0f), color);
            ctx.fill_rect(D2D1::RectF(x_start, cy + 5.0f - bar_h, x_start + bar_w, cy + 5.0f), color);
        }
    }

    // Toggle view mode
    void toggle_view_mode();

    // Update header from diff data
    void set_diff(const FileDiff* diff);

    // Update hunk counter (called by content widget on scroll)
    void update_hunk_display(size_t current, size_t total) {
        if (current_hunk != current || hunk_count != total) {
            current_hunk = current;
            hunk_count = total;
            set_dirty();
        }
    }

    bool should_show_nav() const {
        return hunk_count > 0;
    }

    // Navigation button rect helpers (use widget-local coords)
    // Stats area needs ~100px, toggle button needs ~40px, so nav starts at -160 from right
    static constexpr float NAV_RIGHT_OFFSET = 160.0f;

    D2D1_RECT_F get_nav_prev_rect() const {
        float nav_x = rect.x + rect.width - NAV_TOTAL_WIDTH - NAV_RIGHT_OFFSET;
        float btn_y = rect.y + (HEADER_HEIGHT - NAV_BUTTON_SIZE) / 2.0f;
        return D2D1::RectF(nav_x, btn_y, nav_x + NAV_BUTTON_SIZE, btn_y + NAV_BUTTON_SIZE);
    }

    D2D1_RECT_F get_nav_counter_rect() const {
        float nav_x = rect.x + rect.width - NAV_TOTAL_WIDTH - NAV_RIGHT_OFFSET;
        float counter_x = nav_x + NAV_BUTTON_SIZE + NAV_GAP;
        float counter_y = rect.y + (HEADER_HEIGHT - NAV_BUTTON_SIZE) / 2.0f;
        return D2D1::RectF(counter_x, counter_y, counter_x + NAV_COUNTER_WIDTH, counter_y + NAV_BUTTON_SIZE);
    }

    D2D1_RECT_F get_nav_next_rect() const {
        float nav_x = rect.x + rect.width - NAV_TOTAL_WIDTH - NAV_RIGHT_OFFSET;
        float next_x = nav_x + NAV_BUTTON_SIZE + NAV_GAP + NAV_COUNTER_WIDTH + NAV_GAP;
        float btn_y = rect.y + (HEADER_HEIGHT - NAV_BUTTON_SIZE) / 2.0f;
        return D2D1::RectF(next_x, btn_y, next_x + NAV_BUTTON_SIZE, btn_y + NAV_BUTTON_SIZE);
    }

    static bool point_in_rect(float px, float py, const D2D1_RECT_F& r) {
        return px >= r.left && px <= r.right && py >= r.top && py <= r.bottom;
    }

    // Draw arrow with stem (↑ ↓ style)
    void draw_nav_arrow(RenderContext& ctx, float cx, float cy, bool up, uint32_t color) {
        ctx.brush->SetColor(color_from_argb(color));
        constexpr float head_size = 3.5f;
        constexpr float stem_len = 4.0f;
        constexpr float stroke = 1.5f;

        if (up) {
            float tip_y = cy - stem_len;
            float base_y = cy + stem_len;
            ctx.target->DrawLine(D2D1::Point2F(cx, tip_y), D2D1::Point2F(cx - head_size, tip_y + head_size), ctx.brush, stroke);
            ctx.target->DrawLine(D2D1::Point2F(cx, tip_y), D2D1::Point2F(cx + head_size, tip_y + head_size), ctx.brush, stroke);
            ctx.target->DrawLine(D2D1::Point2F(cx, tip_y), D2D1::Point2F(cx, base_y), ctx.brush, stroke);
        } else {
            float tip_y = cy + stem_len;
            float base_y = cy - stem_len;
            ctx.target->DrawLine(D2D1::Point2F(cx, tip_y), D2D1::Point2F(cx - head_size, tip_y - head_size), ctx.brush, stroke);
            ctx.target->DrawLine(D2D1::Point2F(cx, tip_y), D2D1::Point2F(cx + head_size, tip_y - head_size), ctx.brush, stroke);
            ctx.target->DrawLine(D2D1::Point2F(cx, base_y), D2D1::Point2F(cx, tip_y), ctx.brush, stroke);
        }
    }

    void render(RenderContext& ctx) override {
        if (!(flags & WidgetFlags::Visible)) return;

        // Background
        D2D1_RECT_F header_rect = D2D1::RectF(rect.x, rect.y, rect.x + rect.width, rect.y + HEADER_HEIGHT);
        ctx.fill_rect(header_rect, Theme::BG_TERTIARY);

        // Bottom border
        D2D1_RECT_F border = D2D1::RectF(rect.x, rect.y + HEADER_HEIGHT - 1.0f, rect.x + rect.width, rect.y + HEADER_HEIGHT);
        ctx.fill_rect(border, Theme::BORDER);

        if (!header_path[0]) return;

        // Calculate path rect width based on whether nav is shown
        float path_right = rect.x + rect.width - NAV_RIGHT_OFFSET;
        if (should_show_nav()) {
            path_right -= NAV_TOTAL_WIDTH + 16.0f;
        }

        // File path
        if (g_text_format_path) {
            D2D1_RECT_F path_rect = D2D1::RectF(rect.x + 12.0f, rect.y + 4.0f, path_right, rect.y + HEADER_HEIGHT - 4.0f);
            ctx.draw_text(header_path, static_cast<UINT32>(wcslen(header_path)), g_text_format_path, path_rect, Theme::TEXT_PRIMARY);
        }

        // Navigation buttons
        if (should_show_nav() && g_text_format_body) {
            render_nav_buttons(ctx);
        }

        // Stats (+X -Y) - shifted left to make room for toggle button
        float stats_offset = TOGGLE_BUTTON_SIZE + TOGGLE_BUTTON_MARGIN + 8.0f;
        if (g_text_format_body) {
            wchar_t add_str[32];
            swprintf_s(add_str, L"+%d", additions);
            D2D1_RECT_F add_rect = D2D1::RectF(rect.x + rect.width - 100.0f - stats_offset, rect.y + 8.0f, rect.x + rect.width - 60.0f - stats_offset, rect.y + HEADER_HEIGHT - 8.0f);
            ctx.draw_text(add_str, static_cast<UINT32>(wcslen(add_str)), g_text_format_body, add_rect, Theme::STATUS_ADDED);

            wchar_t del_str[32];
            swprintf_s(del_str, L"-%d", deletions);
            D2D1_RECT_F del_rect = D2D1::RectF(rect.x + rect.width - 55.0f - stats_offset, rect.y + 8.0f, rect.x + rect.width - 12.0f - stats_offset, rect.y + HEADER_HEIGHT - 8.0f);
            ctx.draw_text(del_str, static_cast<UINT32>(wcslen(del_str)), g_text_format_body, del_rect, Theme::STATUS_DELETED);
        }

        // View mode toggle button (far right)
        D2D1_RECT_F toggle_rect = get_toggle_rect();
        uint32_t toggle_bg = toggle_pressed ? Theme::ACCENT : (toggle_hovered ? Theme::BG_HOVER : 0);
        if (toggle_bg != 0) {
            D2D1_ROUNDED_RECT toggle_rounded = D2D1::RoundedRect(toggle_rect, 3.0f, 3.0f);
            ctx.brush->SetColor(color_from_argb(toggle_bg));
            ctx.target->FillRoundedRectangle(toggle_rounded, ctx.brush);
        }
        uint32_t toggle_color = toggle_hovered ? Theme::TEXT_PRIMARY : Theme::TEXT_SECONDARY;
        // Show the OPPOSITE mode icon (what clicking will switch to)
        bool show_sbs_icon = (view_mode == DiffViewMode::Inline);
        draw_toggle_icon(ctx, toggle_rect, show_sbs_icon, toggle_color);
    }

    void render_nav_buttons(RenderContext& ctx) {
        // Previous button
        D2D1_RECT_F prev_rect = get_nav_prev_rect();
        uint32_t prev_bg = nav_prev_pressed ? Theme::ACCENT : (nav_prev_hovered ? Theme::BG_HOVER : 0);
        if (prev_bg != 0) {
            D2D1_ROUNDED_RECT prev_rounded = D2D1::RoundedRect(prev_rect, 3.0f, 3.0f);
            ctx.brush->SetColor(color_from_argb(prev_bg));
            ctx.target->FillRoundedRectangle(prev_rounded, ctx.brush);
        }
        float prev_cx = (prev_rect.left + prev_rect.right) / 2.0f;
        float prev_cy = (prev_rect.top + prev_rect.bottom) / 2.0f;
        uint32_t prev_color = nav_prev_hovered ? Theme::TEXT_PRIMARY : Theme::TEXT_SECONDARY;
        draw_nav_arrow(ctx, prev_cx, prev_cy, true, prev_color);

        // Counter
        D2D1_RECT_F counter_rect = get_nav_counter_rect();
        wchar_t counter_str[32];
        swprintf_s(counter_str, L"%zu/%zu", current_hunk + 1, hunk_count);

        IDWriteTextLayout* counter_layout = nullptr;
        g_dwrite_factory->CreateTextLayout(counter_str, static_cast<UINT32>(wcslen(counter_str)),
            g_text_format_body, NAV_COUNTER_WIDTH, NAV_BUTTON_SIZE, &counter_layout);
        if (counter_layout) {
            counter_layout->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_CENTER);
            counter_layout->SetParagraphAlignment(DWRITE_PARAGRAPH_ALIGNMENT_CENTER);
            ctx.brush->SetColor(color_from_argb(Theme::TEXT_SECONDARY));
            ctx.target->DrawTextLayout(D2D1::Point2F(counter_rect.left, counter_rect.top), counter_layout, ctx.brush);
            counter_layout->Release();
        }

        // Next button
        D2D1_RECT_F next_rect = get_nav_next_rect();
        uint32_t next_bg = nav_next_pressed ? Theme::ACCENT : (nav_next_hovered ? Theme::BG_HOVER : 0);
        if (next_bg != 0) {
            D2D1_ROUNDED_RECT next_rounded = D2D1::RoundedRect(next_rect, 3.0f, 3.0f);
            ctx.brush->SetColor(color_from_argb(next_bg));
            ctx.target->FillRoundedRectangle(next_rounded, ctx.brush);
        }
        float next_cx = (next_rect.left + next_rect.right) / 2.0f;
        float next_cy = (next_rect.top + next_rect.bottom) / 2.0f;
        uint32_t next_color = nav_next_hovered ? Theme::TEXT_PRIMARY : Theme::TEXT_SECONDARY;
        draw_nav_arrow(ctx, next_cx, next_cy, false, next_color);
    }

    // Navigate functions - delegate to content widget
    void navigate_prev_hunk();
    void navigate_next_hunk();

    bool on_mouse_move(float x, float y) override {
        // Coords are widget-relative, convert to absolute for hit testing
        float abs_x = rect.x + x;
        float abs_y = rect.y + y;

        bool was_hovered = nav_prev_hovered || nav_next_hovered || toggle_hovered;

        // Nav buttons
        if (should_show_nav()) {
            nav_prev_hovered = point_in_rect(abs_x, abs_y, get_nav_prev_rect());
            nav_next_hovered = point_in_rect(abs_x, abs_y, get_nav_next_rect());
        } else {
            nav_prev_hovered = false;
            nav_next_hovered = false;
        }

        // Toggle button
        toggle_hovered = point_in_rect(abs_x, abs_y, get_toggle_rect());

        if (was_hovered || nav_prev_hovered || nav_next_hovered || toggle_hovered) {
            set_dirty();
        }

        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        if (button != 0) return false;

        float abs_x = rect.x + x;
        float abs_y = rect.y + y;

        // Nav buttons
        if (should_show_nav()) {
            if (point_in_rect(abs_x, abs_y, get_nav_prev_rect())) {
                nav_prev_pressed = true;
                set_dirty();
                return true;
            }
            if (point_in_rect(abs_x, abs_y, get_nav_next_rect())) {
                nav_next_pressed = true;
                set_dirty();
                return true;
            }
        }

        // Toggle button
        if (point_in_rect(abs_x, abs_y, get_toggle_rect())) {
            toggle_pressed = true;
            set_dirty();
            return true;
        }

        return false;
    }

    bool on_mouse_up(float x, float y, int button) override {
        if (button != 0) return false;

        bool was_pressed = nav_prev_pressed || nav_next_pressed || toggle_pressed;
        float abs_x = rect.x + x;
        float abs_y = rect.y + y;

        // Nav buttons
        if (nav_prev_pressed && point_in_rect(abs_x, abs_y, get_nav_prev_rect())) {
            navigate_prev_hunk();
        }
        if (nav_next_pressed && point_in_rect(abs_x, abs_y, get_nav_next_rect())) {
            navigate_next_hunk();
        }

        // Toggle button
        if (toggle_pressed && point_in_rect(abs_x, abs_y, get_toggle_rect())) {
            toggle_view_mode();
        }

        nav_prev_pressed = false;
        nav_next_pressed = false;
        toggle_pressed = false;
        if (was_pressed) set_dirty();
        return was_pressed;
    }

    bool on_mouse_leave() override {
        nav_prev_hovered = false;
        nav_next_hovered = false;
        nav_prev_pressed = false;
        nav_next_pressed = false;
        toggle_hovered = false;
        toggle_pressed = false;
        set_dirty();
        return false;
    }
};

// ============================================================================
// Main diff viewer container with virtualized rendering
// ============================================================================

struct DiffViewerWidget : Widget {
    // Data
    const FileDiff* diff = nullptr;
    DiffLineIndex line_index;

    // Side-by-side mode support
    DiffViewMode view_mode = DiffViewMode::SideBySide;  // Default to side-by-side
    SideBySideLineIndex sbs_index;
    DiffGutterWidget* center_gutter = nullptr;
    float pane_split_ratio = 0.5f;  // 0.0-1.0, 0.5 = centered

    // Pool for line widgets
    DiffLinePool line_pool;
    bool pool_initialized = false;

    // Layout constants
    static constexpr float LINE_HEIGHT = DiffViewer::LINE_HEIGHT;
    static constexpr float HEADER_HEIGHT = DiffViewer::HEADER_HEIGHT;
    static constexpr int OVERSCAN_LINES = 10;  // Lines above/below viewport

    // Viewport (from ScrollContainer via on_viewport_changed)
    float viewport_top = 0.0f;
    float viewport_bottom = 0.0f;
    float scroll_y = 0.0f;
    bool external_scroll = true;

    // Currently bound range (line indices)
    size_t bound_first = 0;
    size_t bound_last = 0;

    // Horizontal scrolling (synchronized between panes)
    float scroll_x = 0.0f;              // Shared horizontal scroll position
    float max_line_width_left = 0.0f;   // Max content width in left pane
    float max_line_width_right = 0.0f;  // Max content width in right pane

    // Horizontal scrollbar state
    enum class HScrollbarHover { None, LeftButton, RightButton, Thumb, Track };
    HScrollbarHover h_scrollbar_hover_left = HScrollbarHover::None;
    HScrollbarHover h_scrollbar_hover_right = HScrollbarHover::None;
    bool h_scrollbar_dragging = false;     // Drag in progress (either pane)
    float h_drag_start_x = 0.0f;           // Mouse X when drag started
    float h_drag_start_scroll = 0.0f;      // scroll_x when drag started

    // Horizontal scrollbar geometry caches (computed in layout)
    float h_thumb_left = 0.0f;             // Left edge of thumb (relative to track start)
    float h_thumb_width = 0.0f;            // Width of thumb
    float h_track_width = 0.0f;            // Available track width (pane width - buttons)
    float h_max_scroll = 0.0f;             // Maximum scroll_x value

    // Scrollbar constants (reuse from DiffViewer namespace)
    static constexpr float H_SCROLLBAR_HEIGHT = DiffViewer::SCROLLBAR_WIDTH;  // 14.0f
    static constexpr float H_SCROLLBAR_BUTTON_SIZE = DiffViewer::SCROLLBAR_BUTTON_SIZE;  // 14.0f
    static constexpr float H_SCROLLBAR_MIN_THUMB = DiffViewer::SCROLLBAR_MIN_THUMB;  // 30.0f
    static constexpr float H_SCROLLBAR_THUMB_MARGIN = DiffViewer::SCROLLBAR_THUMB_MARGIN;  // 2.0f

    // Active widgets for current viewport
    // In inline mode: maps line_index -> widget
    // In side-by-side mode: maps (pair_index, pane_side) -> widget
    static constexpr size_t MAX_ACTIVE = DiffLinePool::POOL_SIZE;
    struct ActiveBinding {
        size_t line_index;      // For inline mode: line index; for SBS: pair index
        DiffLineWidget* widget;
        DiffPaneSide pane_side; // Only used in side-by-side mode
    };
    ActiveBinding active_widgets[MAX_ACTIVE] = {};
    size_t active_count = 0;

    // Side-by-side mode bound range
    size_t sbs_bound_first = 0;
    size_t sbs_bound_last = 0;

    // Hunk navigation state
    size_t current_hunk = 0;           // Currently visible hunk for counter display (0-based, scroll-based)
    size_t nav_target = 0;             // Navigation target (0-based, only changed by buttons)

    // Scroll animation state
    float scroll_target = 0.0f;        // Target scroll position for animation
    float scroll_anim_start = 0.0f;    // Animation start position
    float scroll_anim_progress = 0.0f; // Animation progress (0-1)
    bool scroll_animating = false;     // Whether animation is in progress
    AnimGuard scroll_guard;            // Scheduler registration — RAII-safe on destroy
    static constexpr float SCROLL_ANIM_DURATION = 0.25f;  // Animation duration in seconds (250ms)

    // Reference to parent scroll container (for scroll animation)
    ScrollContainer* scroll_container = nullptr;

    // Reference to header widget (for updating hunk counter display)
    DiffHeaderWidget* header_widget = nullptr;

    // Track current file for saving position
    char current_file_path[Git::MAX_PATH_LEN] = {};

    // Callback for context menu (right-click)
    void (*on_context_menu)(DiffViewerWidget* viewer, int line_index,
                            float screen_x, float screen_y, void* user_data) = nullptr;
    void* context_menu_user_data = nullptr;

    DiffViewerWidget() : Widget() {
        debug_name = "DiffViewerWidget";
        flags |= WidgetFlags::RendersOwnChildren;  // We handle child rendering
        line_index.line_height = LINE_HEIGHT;
        sbs_index.line_height = LINE_HEIGHT;
    }

    // Force layout update (call after split ratio changes during drag)
    void force_layout_update() {
        if (view_mode == DiffViewMode::SideBySide) {
            update_visible_range_sbs();
        } else {
            update_visible_range();
        }
        set_dirty();
    }

    // Set the center gutter widget (for both modes)
    void set_center_gutter(DiffGutterWidget* gutter) {
        center_gutter = gutter;
        if (center_gutter) {
            center_gutter->parent = this;  // Needed for drag calculations
            center_gutter->set_split_ratio_ptr(&pane_split_ratio);
            center_gutter->set_sbs_index(&sbs_index);
            center_gutter->set_line_index(&line_index);
            center_gutter->set_mode(view_mode == DiffViewMode::Inline);

            // Set up callback to trigger layout when ratio changes
            center_gutter->on_split_changed = [](float new_ratio, void* user_data) {
                (void)new_ratio;
                DiffViewerWidget* viewer = static_cast<DiffViewerWidget*>(user_data);
                if (viewer) {
                    viewer->force_layout_update();
                }
            };
            center_gutter->split_changed_user_data = this;
        }
    }

    // Set view mode with scroll position mapping
    void set_view_mode(DiffViewMode mode) {
        if (view_mode == mode) return;

        // Map scroll position from old mode to new mode
        float new_scroll_y = 0.0f;
        float current_scroll = scroll_container ? scroll_container->scroll_y : scroll_y;

        if (mode == DiffViewMode::SideBySide && view_mode == DiffViewMode::Inline) {
            // Inline -> SideBySide
            // Find top-visible line in inline mode
            size_t top_line = line_index.first_visible_index(current_scroll);
            if (top_line < line_index.count && line_index.entries[top_line].line) {
                DiffLine* target_line = line_index.entries[top_line].line;
                // Find this line in side-by-side pairs
                for (size_t i = 0; i < sbs_index.pair_count; i++) {
                    SideBySidePair& pair = sbs_index.pairs[i];
                    if (pair.left_line == target_line || pair.right_line == target_line) {
                        new_scroll_y = pair.y_offset;
                        break;
                    }
                }
            }
        } else if (mode == DiffViewMode::Inline && view_mode == DiffViewMode::SideBySide) {
            // SideBySide -> Inline
            // Find top-visible pair in side-by-side mode
            size_t top_pair = sbs_index.first_visible_index(current_scroll);
            if (top_pair < sbs_index.pair_count) {
                SideBySidePair& pair = sbs_index.pairs[top_pair];
                DiffLine* target_line = pair.left_line ? pair.left_line : pair.right_line;
                if (target_line) {
                    // Find this line in inline index
                    for (size_t i = 0; i < line_index.count; i++) {
                        if (line_index.entries[i].line == target_line) {
                            new_scroll_y = line_index.entries[i].y_offset;
                            break;
                        }
                    }
                }
            }
        }

        // Switch mode
        view_mode = mode;
        release_all_active();
        bound_first = 0;
        bound_last = 0;
        sbs_bound_first = 0;
        sbs_bound_last = 0;

        // Update gutter mode for correct indicator rendering
        if (center_gutter) {
            center_gutter->set_mode(mode == DiffViewMode::Inline);
        }

        // Update preferred height for new mode
        if (view_mode == DiffViewMode::SideBySide) {
            preferred_height = sbs_index.total_height;
        } else {
            preferred_height = line_index.total_height;
        }

        // Apply mapped scroll position and update ScrollContainer's horizontal scrollbar
        if (scroll_container) {
            scroll_container->content_height = preferred_height;
            scroll_container->scroll_to(new_scroll_y);
            // Side-by-side mode: we handle horizontal scrolling ourselves
            // Inline mode: use ScrollContainer's horizontal scrollbar for wide lines
            scroll_container->show_scrollbar_h = (mode == DiffViewMode::Inline);
        }

        set_dirty();
    }

    // Set the scroll container for navigation
    void set_scroll_container(ScrollContainer* sc) {
        scroll_container = sc;
    }

    // Set the header widget for updating hunk counter
    void set_header_widget(DiffHeaderWidget* hw) {
        header_widget = hw;
    }

    // Initialize the pool (called once)
    void init_pool(WidgetArena& arena) {
        if (!pool_initialized) {
            line_pool.init(arena);
            pool_initialized = true;
        }
    }

    // Save current scroll position to cache
    void save_scroll_position() {
        if (!scroll_container || current_file_path[0] == '\0') return;
        DiffScrollCache::save(current_file_path, scroll_container->scroll_y);
    }

    // Jump to scroll position immediately (no animation)
    void jump_to_scroll_position(float pos) {
        if (!scroll_container) return;
        if (scroll_animating) {
            scroll_animating = false;
            scroll_guard.stop();
        }
        // Update scroll container's content_height BEFORE scrolling to avoid
        // incorrect clamping (content_height may still reflect previous diff)
        scroll_container->content_height = preferred_height;
        scroll_container->scroll_to(pos);
    }

    // Set the diff to display
    void set_diff(const FileDiff* new_diff) {
        // Save scroll position of previous file before switching
        save_scroll_position();

        // Release all active widgets
        release_all_active();

        diff = new_diff;

        // Rebuild indices for both modes
        line_index.build_from_diff(diff, LINE_HEIGHT);
        sbs_index.build_from_diff(diff, LINE_HEIGHT);

        // Update center gutter with new index
        if (center_gutter) {
            center_gutter->set_sbs_index(&sbs_index);
        }

        // Track current file path for scroll cache
        if (diff) {
            strcpy_s(current_file_path, diff->path);
        } else {
            current_file_path[0] = '\0';
        }

        // Update header widget
        if (header_widget) {
            header_widget->set_diff(diff);
        }

        // Reset scroll and viewport
        scroll_y = 0.0f;
        scroll_x = 0.0f;  // Reset horizontal scroll for new file
        bound_first = 0;
        bound_last = 0;
        sbs_bound_first = 0;
        sbs_bound_last = 0;
        max_line_width_left = 0.0f;   // Reset max width for horizontal scrolling
        max_line_width_right = 0.0f;

        // Update preferred size based on view mode
        if (view_mode == DiffViewMode::SideBySide) {
            preferred_height = sbs_index.total_height;
        } else {
            preferred_height = line_index.total_height;
        }
        preferred_width = 800.0f;  // Minimum width, will grow based on content

        set_dirty();

        // Reset navigation state for new file
        current_hunk = 0;
        nav_target = 0;

        // Restore scroll position or jump to first hunk (immediate, no animation)
        if (diff) {
            float cached_pos = 0.0f;
            if (DiffScrollCache::get(diff->path, &cached_pos)) {
                // Restore previous scroll position
                jump_to_scroll_position(cached_pos);
            } else if (line_index.hunk_region_count > 0 && line_index.hunk_first_change) {
                // First time viewing this file - jump to first hunk immediately
                size_t target_line = line_index.hunk_first_change[0];
                if (target_line >= line_index.count) target_line = 0;

                // Show context above first change
                const size_t CONTEXT_ABOVE = 8;
                if (target_line >= CONTEXT_ABOVE) {
                    target_line -= CONTEXT_ABOVE;
                } else {
                    target_line = 0;
                }

                float target_scroll = line_index.entries[target_line].y_offset;
                jump_to_scroll_position(target_scroll);
            }
        }
    }

    // Animation tick for smooth scrolling
    void tick(float dt) override {
        Widget::tick(dt);  // Call base class

        if (!scroll_animating || !scroll_container) return;

        // Progress animation
        scroll_anim_progress += dt / SCROLL_ANIM_DURATION;

        if (scroll_anim_progress >= 1.0f) {
            // Animation complete
            scroll_anim_progress = 1.0f;
            scroll_animating = false;
            scroll_guard.stop();
            scroll_container->scroll_to(scroll_target);
        } else {
            // Ease-out interpolation: 1 - (1-t)^2
            float t = scroll_anim_progress;
            float eased = 1.0f - (1.0f - t) * (1.0f - t);
            float current = scroll_anim_start + (scroll_target - scroll_anim_start) * eased;
            scroll_container->scroll_to(current);
        }
        set_dirty();
    }

    // Called by ScrollContainer when viewport changes
    void on_viewport_changed(float vp_top, float vp_bottom) override {
        if (external_scroll) {
            viewport_top = vp_top;
            viewport_bottom = vp_bottom;
            // Calculate actual scroll offset (viewport_top is fixed, rect.y decreases as we scroll)
            scroll_y = viewport_top - rect.y;

            // Update center gutter scroll state
            if (center_gutter) {
                center_gutter->update_scroll(scroll_y, vp_bottom - vp_top);
            }

            // Update visible range based on view mode
            if (view_mode == DiffViewMode::SideBySide) {
                update_visible_range_sbs();
            } else {
                update_visible_range();
            }

            // Update current hunk for live counter
            update_current_hunk();
        }
    }

    // Release all active widget bindings
    void release_all_active() {
        for (size_t i = 0; i < active_count; i++) {
            if (active_widgets[i].widget) {
                line_pool.release(active_widgets[i].widget);
            }
        }
        active_count = 0;
    }

    // Find if we have an active widget for a given line index (inline mode)
    DiffLineWidget* find_active_widget(size_t line_idx) {
        for (size_t i = 0; i < active_count; i++) {
            if (active_widgets[i].line_index == line_idx &&
                active_widgets[i].pane_side == DiffPaneSide::Full) {
                return active_widgets[i].widget;
            }
        }
        return nullptr;
    }

    // Find if we have an active widget for a given pair index and pane side (SBS mode)
    DiffLineWidget* find_active_widget_sbs(size_t pair_idx, DiffPaneSide side) {
        for (size_t i = 0; i < active_count; i++) {
            if (active_widgets[i].line_index == pair_idx &&
                active_widgets[i].pane_side == side) {
                return active_widgets[i].widget;
            }
        }
        return nullptr;
    }

    // Remove an active binding by line index (inline mode)
    void remove_active_binding(size_t line_idx) {
        for (size_t i = 0; i < active_count; i++) {
            if (active_widgets[i].line_index == line_idx &&
                active_widgets[i].pane_side == DiffPaneSide::Full) {
                if (active_widgets[i].widget) {
                    line_pool.release(active_widgets[i].widget);
                }
                // Move last element to fill gap
                if (i < active_count - 1) {
                    active_widgets[i] = active_widgets[active_count - 1];
                }
                active_count--;
                return;
            }
        }
    }

    // Add an active binding (inline mode)
    void add_active_binding(size_t line_idx, DiffLineWidget* widget) {
        if (active_count < MAX_ACTIVE) {
            active_widgets[active_count].line_index = line_idx;
            active_widgets[active_count].widget = widget;
            active_widgets[active_count].pane_side = DiffPaneSide::Full;
            active_count++;
        }
    }

    // Add an active binding with pane side (SBS mode)
    void add_active_binding_sbs(size_t pair_idx, DiffLineWidget* widget, DiffPaneSide side) {
        if (active_count < MAX_ACTIVE) {
            active_widgets[active_count].line_index = pair_idx;
            active_widgets[active_count].widget = widget;
            active_widgets[active_count].pane_side = side;
            active_count++;
        }
    }

    // Update visible range and recycle widgets
    void update_visible_range() {
        if (line_index.count == 0) {
            release_all_active();
            return;
        }

        // Skip if viewport hasn't been set yet (will be called again after first render)
        if (viewport_bottom <= viewport_top) {
            return;
        }

        // The scroll offset tells us how far the content has scrolled up
        float scroll_offset = viewport_top - rect.y;

        // Calculate visible range in content-local coordinates
        float visible_top_content = scroll_offset - HEADER_HEIGHT;
        float viewport_height = viewport_bottom - viewport_top;
        float visible_bottom_content = visible_top_content + viewport_height;

        // Clamp to valid range
        if (visible_top_content < 0) visible_top_content = 0;
        if (visible_bottom_content < 0) visible_bottom_content = 0;
        if (visible_bottom_content > line_index.total_height) visible_bottom_content = line_index.total_height;

        // Calculate first and last visible indices
        size_t new_first = line_index.first_visible_index(visible_top_content);
        size_t viewport_lines = line_index.lines_in_viewport(visible_bottom_content - visible_top_content);
        size_t new_last = new_first + viewport_lines;

        // Add overscan buffer
        if (new_first > static_cast<size_t>(OVERSCAN_LINES)) {
            new_first -= OVERSCAN_LINES;
        } else {
            new_first = 0;
        }
        new_last += OVERSCAN_LINES;
        if (new_last > line_index.count) {
            new_last = line_index.count;
        }

        // Calculate layout values needed for positioning
        // In inline mode, also account for center gutter (30px)
        float content_width = rect.width - DiffViewer::GUTTER_WIDTH - DiffViewer::CENTER_GUTTER_WIDTH
                            - DiffViewer::LEFT_BORDER_WIDTH - DiffViewer::CONTENT_PADDING;
        if (content_width < 0.0f) content_width = 0.0f;
        float content_start_x = rect.x;
        float content_start_y = rect.y + HEADER_HEIGHT;

        // Always update positions of existing widgets and ensure layouts are current
        // (rect.y changes when scrolling, rect.width changes when window resizes)
        for (size_t i = 0; i < active_count; i++) {
            size_t line_idx = active_widgets[i].line_index;
            DiffLineWidget* widget = active_widgets[i].widget;
            if (!widget || line_idx >= line_index.count) continue;

            DiffLineEntry* entry = &line_index.entries[line_idx];
            widget->rect.x = content_start_x;
            widget->rect.y = content_start_y + entry->y_offset;
            widget->rect.width = rect.width;
            widget->content_y_offset = entry->y_offset;  // For stripe alignment

            // Ensure layouts are regenerated if width changed (handles window resize)
            widget->ensure_layouts(content_width);

            // Track max content width for horizontal scrolling (use left for inline mode)
            if (widget->actual_content_width > max_line_width_left) {
                max_line_width_left = widget->actual_content_width;
                // Include center gutter in inline mode
                float gutter_total = DiffViewer::GUTTER_WIDTH + DiffViewer::CENTER_GUTTER_WIDTH;
                preferred_width = gutter_total + DiffViewer::LEFT_BORDER_WIDTH
                                + DiffViewer::CONTENT_PADDING + max_line_width_left + 20.0f;
            }
        }

        // Update center gutter position (must happen BEFORE early return)
        // Gutter stays fixed in viewport (doesn't scroll with content)
        if (center_gutter) {
            float gutter_x = rect.x + DiffViewer::GUTTER_WIDTH;
            center_gutter->rect.x = gutter_x;
            center_gutter->rect.y = viewport_top;
            center_gutter->rect.width = DiffViewer::CENTER_GUTTER_WIDTH;
            center_gutter->rect.height = viewport_bottom - viewport_top;
        }

        // If range hasn't changed, we're done after updating positions and layouts
        if (new_first == bound_first && new_last == bound_last) {
            return;
        }

        // Release widgets outside new range
        for (size_t i = active_count; i > 0; ) {
            i--;
            size_t line_idx = active_widgets[i].line_index;
            if (line_idx < new_first || line_idx >= new_last) {
                if (active_widgets[i].widget) {
                    line_pool.release(active_widgets[i].widget);
                }
                // Move last to fill gap
                if (i < active_count - 1) {
                    active_widgets[i] = active_widgets[active_count - 1];
                }
                active_count--;
            }
        }

        // Acquire widgets for new lines in range
        for (size_t idx = new_first; idx < new_last; idx++) {
            // Check if we already have a widget for this line
            if (find_active_widget(idx)) continue;

            // Get line entry
            DiffLineEntry* entry = &line_index.entries[idx];

            // Acquire a widget from pool
            DiffLineWidget* widget = line_pool.acquire();
            if (!widget) {
                // Pool exhausted - shouldn't happen with proper sizing
                break;
            }

            // Bind widget to line
            widget->bind(entry->line, widget->pool_index);

            // Position widget
            widget->rect.x = content_start_x;
            widget->rect.y = content_start_y + entry->y_offset;
            widget->rect.width = rect.width;
            widget->rect.height = LINE_HEIGHT;
            widget->content_y_offset = entry->y_offset;  // For stripe alignment

            // Ensure layouts are created
            widget->ensure_layouts(content_width);

            // Track max content width for horizontal scrolling (use left for inline mode)
            if (widget->actual_content_width > max_line_width_left) {
                max_line_width_left = widget->actual_content_width;
                // Include center gutter in inline mode
                float gutter_total = DiffViewer::GUTTER_WIDTH + DiffViewer::CENTER_GUTTER_WIDTH;
                preferred_width = gutter_total + DiffViewer::LEFT_BORDER_WIDTH
                                + DiffViewer::CONTENT_PADDING + max_line_width_left + 20.0f;
            }

            // Add to active list
            add_active_binding(idx, widget);
        }

        bound_first = new_first;
        bound_last = new_last;

        set_dirty();
    }

    // Update visible range for side-by-side mode
    void update_visible_range_sbs() {
        if (sbs_index.pair_count == 0) {
            release_all_active();
            return;
        }

        // Skip if viewport hasn't been set yet
        if (viewport_bottom <= viewport_top) {
            return;
        }

        // Calculate visible range
        float scroll_offset = viewport_top - rect.y;
        float visible_top_content = scroll_offset - HEADER_HEIGHT;
        float viewport_height = viewport_bottom - viewport_top;
        float visible_bottom_content = visible_top_content + viewport_height;

        // Clamp to valid range
        if (visible_top_content < 0) visible_top_content = 0;
        if (visible_bottom_content < 0) visible_bottom_content = 0;
        if (visible_bottom_content > sbs_index.total_height) visible_bottom_content = sbs_index.total_height;

        // Calculate first and last visible pair indices
        size_t new_first = sbs_index.first_visible_index(visible_top_content);
        size_t viewport_pairs = sbs_index.pairs_in_viewport(visible_bottom_content - visible_top_content);
        size_t new_last = new_first + viewport_pairs;

        // Add overscan buffer
        if (new_first > static_cast<size_t>(OVERSCAN_LINES)) {
            new_first -= OVERSCAN_LINES;
        } else {
            new_first = 0;
        }
        new_last += OVERSCAN_LINES;
        if (new_last > sbs_index.pair_count) {
            new_last = sbs_index.pair_count;
        }

        // Calculate pane layout
        constexpr float GUTTER_WIDTH = DiffViewer::CENTER_GUTTER_WIDTH;
        constexpr float LINE_NUM_WIDTH = DiffViewer::LINE_NUMBER_WIDTH;
        float total_width = rect.width;
        float available_for_panes = total_width - GUTTER_WIDTH;

        float left_pane_width = available_for_panes * pane_split_ratio;
        float right_pane_width = available_for_panes * (1.0f - pane_split_ratio);

        float left_pane_x = rect.x;
        float gutter_x = left_pane_x + left_pane_width;
        float right_pane_x = gutter_x + GUTTER_WIDTH;

        float content_start_y = rect.y + HEADER_HEIGHT;

        // Calculate content width for text layout (single column line number)
        float pane_content_width = left_pane_width - LINE_NUM_WIDTH - DiffViewer::LEFT_BORDER_WIDTH - DiffViewer::CONTENT_PADDING;
        if (pane_content_width < 0.0f) pane_content_width = 0.0f;

        // Update positions of existing widgets
        for (size_t i = 0; i < active_count; i++) {
            size_t pair_idx = active_widgets[i].line_index;
            DiffLineWidget* widget = active_widgets[i].widget;
            DiffPaneSide side = active_widgets[i].pane_side;
            if (!widget || pair_idx >= sbs_index.pair_count) continue;

            SideBySidePair& pair = sbs_index.pairs[pair_idx];
            float pane_x = (side == DiffPaneSide::Left) ? left_pane_x : right_pane_x;
            float pane_w = (side == DiffPaneSide::Left) ? left_pane_width : right_pane_width;

            widget->rect.x = pane_x;
            widget->rect.y = content_start_y + pair.y_offset;
            widget->rect.width = pane_w;
            widget->content_y_offset = pair.y_offset;  // For stripe alignment

            // Re-ensure layouts if width changed
            widget->ensure_layouts(pane_content_width);
        }

        // Update center gutter position (must happen BEFORE early return)
        // Gutter stays fixed in viewport (doesn't scroll with content)
        // Subtract scrollbar height so gutter doesn't overlap the scrollbar area
        if (center_gutter) {
            center_gutter->rect.x = gutter_x;
            center_gutter->rect.y = viewport_top;  // Fixed at viewport top, not content
            center_gutter->rect.width = GUTTER_WIDTH;
            center_gutter->rect.height = viewport_height - H_SCROLLBAR_HEIGHT;
        }

        // If range hasn't changed, we're done (widget positions already updated above)
        if (new_first == sbs_bound_first && new_last == sbs_bound_last) {
            return;
        }

        // Release widgets outside new range
        for (size_t i = active_count; i > 0; ) {
            i--;
            size_t pair_idx = active_widgets[i].line_index;
            if (pair_idx < new_first || pair_idx >= new_last) {
                if (active_widgets[i].widget) {
                    line_pool.release(active_widgets[i].widget);
                }
                if (i < active_count - 1) {
                    active_widgets[i] = active_widgets[active_count - 1];
                }
                active_count--;
            }
        }

        // Acquire widgets for new pairs in range
        for (size_t idx = new_first; idx < new_last; idx++) {
            SideBySidePair& pair = sbs_index.pairs[idx];

            // Left pane widget
            if (!find_active_widget_sbs(idx, DiffPaneSide::Left)) {
                DiffLineWidget* left_widget = line_pool.acquire();
                if (left_widget) {
                    bool is_placeholder = (pair.left_line == nullptr);
                    left_widget->bind_for_pane(pair.left_line, left_widget->pool_index,
                                               DiffPaneSide::Left, is_placeholder);
                    left_widget->rect.x = left_pane_x;
                    left_widget->rect.y = content_start_y + pair.y_offset;
                    left_widget->rect.width = left_pane_width;
                    left_widget->rect.height = LINE_HEIGHT;
                    left_widget->content_y_offset = pair.y_offset;  // For stripe alignment
                    left_widget->ensure_layouts(pane_content_width);
                    add_active_binding_sbs(idx, left_widget, DiffPaneSide::Left);

                    // Track max content width for horizontal scrolling
                    if (left_widget->actual_content_width > max_line_width_left) {
                        max_line_width_left = left_widget->actual_content_width;
                    }
                }
            }

            // Right pane widget
            if (!find_active_widget_sbs(idx, DiffPaneSide::Right)) {
                DiffLineWidget* right_widget = line_pool.acquire();
                if (right_widget) {
                    bool is_placeholder = (pair.right_line == nullptr);
                    right_widget->bind_for_pane(pair.right_line, right_widget->pool_index,
                                                DiffPaneSide::Right, is_placeholder);
                    right_widget->rect.x = right_pane_x;
                    right_widget->rect.y = content_start_y + pair.y_offset;
                    right_widget->rect.width = right_pane_width;
                    right_widget->rect.height = LINE_HEIGHT;
                    right_widget->content_y_offset = pair.y_offset;  // For stripe alignment
                    right_widget->ensure_layouts(pane_content_width);
                    add_active_binding_sbs(idx, right_widget, DiffPaneSide::Right);

                    // Track max content width for horizontal scrolling
                    if (right_widget->actual_content_width > max_line_width_right) {
                        max_line_width_right = right_widget->actual_content_width;
                    }
                }
            }
        }

        sbs_bound_first = new_first;
        sbs_bound_last = new_last;

        set_dirty();
    }

    void measure(const LayoutConstraints& c) override {
        (void)c;
        // Use the correct index based on view mode
        if (view_mode == DiffViewMode::SideBySide) {
            preferred_height = HEADER_HEIGHT + sbs_index.total_height;
        } else {
            preferred_height = HEADER_HEIGHT + line_index.total_height;
        }
        // Use computed max_line_width if available, otherwise minimum width
        float max_width = fmaxf(max_line_width_left, max_line_width_right);
        if (max_width > 0.0f) {
            // Include center gutter width in inline mode
            float gutter_total = DiffViewer::GUTTER_WIDTH;
            if (view_mode == DiffViewMode::Inline) {
                gutter_total += DiffViewer::CENTER_GUTTER_WIDTH;
            }
            preferred_width = gutter_total + DiffViewer::LEFT_BORDER_WIDTH
                            + DiffViewer::CONTENT_PADDING + max_width + 20.0f;
        } else {
            preferred_width = 800.0f;  // Minimum width before content is measured
        }
    }

    void layout() override {
        // Update widget positions after layout change.
        // Must branch on view_mode because active_widgets[i].line_index is
        // an index into line_index.entries[] in Inline mode, but into
        // sbs_index.pairs[] in SideBySide mode — they are different arrays.
        float content_start_y = rect.y + HEADER_HEIGHT;

        if (view_mode == DiffViewMode::SideBySide) {
            // Mirror the geometry computed in update_visible_range_sbs() so
            // that a resize-only relayout repositions widgets correctly even
            // if scroll hasn't moved.
            constexpr float GUTTER_WIDTH = DiffViewer::CENTER_GUTTER_WIDTH;
            constexpr float LINE_NUM_WIDTH = DiffViewer::LINE_NUMBER_WIDTH;
            float available_for_panes = rect.width - GUTTER_WIDTH;
            if (available_for_panes < 0.0f) available_for_panes = 0.0f;
            float left_pane_width = available_for_panes * pane_split_ratio;
            float right_pane_width = available_for_panes * (1.0f - pane_split_ratio);
            float left_pane_x = rect.x;
            float right_pane_x = left_pane_x + left_pane_width + GUTTER_WIDTH;
            float pane_content_width = left_pane_width - LINE_NUM_WIDTH
                                     - DiffViewer::LEFT_BORDER_WIDTH
                                     - DiffViewer::CONTENT_PADDING;
            if (pane_content_width < 0.0f) pane_content_width = 0.0f;

            for (size_t i = 0; i < active_count; i++) {
                size_t pair_idx = active_widgets[i].line_index;
                DiffLineWidget* widget = active_widgets[i].widget;
                DiffPaneSide side = active_widgets[i].pane_side;
                if (!widget || pair_idx >= sbs_index.pair_count) continue;

                SideBySidePair& pair = sbs_index.pairs[pair_idx];
                float pane_x = (side == DiffPaneSide::Left) ? left_pane_x : right_pane_x;
                float pane_w = (side == DiffPaneSide::Left) ? left_pane_width : right_pane_width;

                widget->rect.x = pane_x;
                widget->rect.y = content_start_y + pair.y_offset;
                widget->rect.width = pane_w;
                widget->rect.height = LINE_HEIGHT;
                widget->content_y_offset = pair.y_offset;
                widget->ensure_layouts(pane_content_width);
            }
            return;
        }

        // Inline mode
        float content_width = rect.width - DiffViewer::GUTTER_WIDTH - DiffViewer::CENTER_GUTTER_WIDTH
                            - DiffViewer::LEFT_BORDER_WIDTH - DiffViewer::CONTENT_PADDING;
        if (content_width < 0.0f) content_width = 0.0f;

        for (size_t i = 0; i < active_count; i++) {
            size_t line_idx = active_widgets[i].line_index;
            DiffLineWidget* widget = active_widgets[i].widget;
            if (!widget || line_idx >= line_index.count) continue;

            DiffLineEntry* entry = &line_index.entries[line_idx];
            widget->rect.x = rect.x;
            widget->rect.y = content_start_y + entry->y_offset;
            widget->rect.width = rect.width;
            widget->rect.height = LINE_HEIGHT;
            widget->content_y_offset = entry->y_offset;  // For stripe alignment

            // Re-ensure layouts if width changed
            widget->ensure_layouts(content_width);

            // Track max content width for horizontal scrolling
            if (widget->actual_content_width > max_line_width_left) {
                max_line_width_left = widget->actual_content_width;
                float gutter_total = DiffViewer::GUTTER_WIDTH + DiffViewer::CENTER_GUTTER_WIDTH;
                preferred_width = gutter_total + DiffViewer::LEFT_BORDER_WIDTH
                                + DiffViewer::CONTENT_PADDING + max_line_width_left + 20.0f;
            }
        }
    }

    // ========================================================================
    // Hunk Navigation
    // ========================================================================

    // Determine which hunk is visible at the top of the viewport (for counter display)
    // Note: This only updates current_hunk (display), NOT nav_target (button state)
    void update_current_hunk() {
        size_t old_hunk = current_hunk;

        if (line_index.hunk_region_count == 0) {
            current_hunk = 0;
        } else {
            // Find the first visible line
            size_t first_visible = line_index.first_visible_index(scroll_y);

            // Search backwards from first visible to find which hunk we're in
            // or search forward if we're before all hunks
            bool found = false;
            for (size_t i = first_visible; i < line_index.count && !found; i++) {
                if (line_index.entries[i].hunk_index != UINT32_MAX) {
                    current_hunk = line_index.entries[i].hunk_index;
                    found = true;
                }
            }

            // If no hunk found forward, search backward
            if (!found && first_visible > 0) {
                for (size_t i = first_visible; i > 0; i--) {
                    if (line_index.entries[i - 1].hunk_index != UINT32_MAX) {
                        current_hunk = line_index.entries[i - 1].hunk_index;
                        found = true;
                        break;
                    }
                }
            }

            if (!found) {
                current_hunk = 0;
            }
        }

        // Notify header widget of hunk change
        if (header_widget && (old_hunk != current_hunk || line_index.hunk_region_count > 0)) {
            header_widget->update_hunk_display(current_hunk, line_index.hunk_region_count);
        }
    }

    // Navigate to a specific hunk index
    void navigate_to_hunk(size_t hunk_index) {
        if (line_index.hunk_region_count == 0 || !line_index.hunk_first_change) return;
        if (hunk_index >= line_index.hunk_region_count) return;
        if (!scroll_container) return;  // Need scroll container for animation

        // Get the line index for the first change in this hunk
        size_t target_line = line_index.hunk_first_change[hunk_index];
        if (target_line >= line_index.count) return;

        // Calculate scroll position to show context above the hunk
        // Show ~8 lines of context above the first change
        const size_t CONTEXT_ABOVE = 8;
        if (target_line >= CONTEXT_ABOVE) {
            target_line -= CONTEXT_ABOVE;
        } else {
            target_line = 0;
        }

        float target_scroll = line_index.entries[target_line].y_offset;

        // Start smooth scroll animation (interrupt any existing).
        // AnimGuard is idempotent — safe to call start() while already active.
        scroll_guard.start();
        scroll_anim_start = scroll_container->scroll_y;
        scroll_target = target_scroll;
        scroll_anim_progress = 0.0f;
        scroll_animating = true;
        // Note: Don't set current_hunk here - it's updated by scroll position.
        // nav_target is set by the caller (navigate_prev/next_hunk).
    }

    // Navigate to previous hunk (with wrap)
    // Uses nav_target (button state), not current_hunk (display state)
    void navigate_prev_hunk() {
        if (line_index.hunk_region_count == 0) return;
        nav_target = (nav_target == 0) ? line_index.hunk_region_count - 1 : nav_target - 1;
        navigate_to_hunk(nav_target);
    }

    // Navigate to next hunk (with wrap)
    // Uses nav_target (button state), not current_hunk (display state)
    void navigate_next_hunk() {
        if (line_index.hunk_region_count == 0) return;
        nav_target = (nav_target + 1 >= line_index.hunk_region_count) ? 0 : nav_target + 1;
        navigate_to_hunk(nav_target);
    }

    // ========================================================================
    // Horizontal Scrollbar Rendering
    // ========================================================================

    void draw_h_arrow(RenderContext& ctx, float cx, float cy, bool left) {
        ctx.brush->SetColor(color_from_argb(Theme::TEXT_MUTED));
        float size = 4.0f;
        if (left) {
            // Left arrow: point at left
            ctx.target->DrawLine(D2D1::Point2F(cx - size, cy), D2D1::Point2F(cx + size / 2.0f, cy - size), ctx.brush, 1.0f);
            ctx.target->DrawLine(D2D1::Point2F(cx - size, cy), D2D1::Point2F(cx + size / 2.0f, cy + size), ctx.brush, 1.0f);
        } else {
            // Right arrow: point at right
            ctx.target->DrawLine(D2D1::Point2F(cx + size, cy), D2D1::Point2F(cx - size / 2.0f, cy - size), ctx.brush, 1.0f);
            ctx.target->DrawLine(D2D1::Point2F(cx + size, cy), D2D1::Point2F(cx - size / 2.0f, cy + size), ctx.brush, 1.0f);
        }
    }

    // Calculate max scroll based on max content width and pane width
    float calculate_max_scroll_x(float pane_width) const {
        constexpr float LINE_NUM_WIDTH = DiffViewer::LINE_NUMBER_WIDTH;
        constexpr float BORDER_WIDTH = DiffViewer::LEFT_BORDER_WIDTH;
        constexpr float CONTENT_PAD = DiffViewer::CONTENT_PADDING;

        float content_area_width = pane_width - LINE_NUM_WIDTH - BORDER_WIDTH - CONTENT_PAD;
        if (content_area_width <= 0.0f) return 0.0f;

        float max_content = fmaxf(max_line_width_left, max_line_width_right);
        return fmaxf(0.0f, max_content - content_area_width);
    }

    // Render horizontal scrollbar for a single pane
    // pane_x, pane_width: the pane's position and width
    // sb_y: Y position of the scrollbar (bottom of viewport)
    // is_left_pane: which pane (for hover state tracking)
    void render_h_scrollbar(RenderContext& ctx, float pane_x, float pane_width, float sb_y, bool is_left_pane) {
        // Calculate if scrollbar is needed
        float max_scroll = calculate_max_scroll_x(pane_width);
        if (max_scroll <= 0.0f) {
            // No scrolling needed - just draw empty track
            D2D1_RECT_F track_rect = D2D1::RectF(pane_x, sb_y, pane_x + pane_width, sb_y + H_SCROLLBAR_HEIGHT);
            ctx.fill_rect(track_rect, Theme::BG_SECONDARY);
            return;
        }

        // Track background
        D2D1_RECT_F track_rect = D2D1::RectF(pane_x, sb_y, pane_x + pane_width, sb_y + H_SCROLLBAR_HEIGHT);
        ctx.fill_rect(track_rect, Theme::BG_SECONDARY);

        // Get hover state for this pane
        HScrollbarHover hover = is_left_pane ? h_scrollbar_hover_left : h_scrollbar_hover_right;

        // Left button
        D2D1_RECT_F left_btn = D2D1::RectF(pane_x, sb_y, pane_x + H_SCROLLBAR_BUTTON_SIZE, sb_y + H_SCROLLBAR_HEIGHT);
        if (hover == HScrollbarHover::LeftButton) {
            ctx.fill_rect(left_btn, Theme::BG_TERTIARY);
        }
        draw_h_arrow(ctx, pane_x + H_SCROLLBAR_BUTTON_SIZE / 2.0f, sb_y + H_SCROLLBAR_HEIGHT / 2.0f, true);

        // Right button
        float right_btn_x = pane_x + pane_width - H_SCROLLBAR_BUTTON_SIZE;
        D2D1_RECT_F right_btn = D2D1::RectF(right_btn_x, sb_y, right_btn_x + H_SCROLLBAR_BUTTON_SIZE, sb_y + H_SCROLLBAR_HEIGHT);
        if (hover == HScrollbarHover::RightButton) {
            ctx.fill_rect(right_btn, Theme::BG_TERTIARY);
        }
        draw_h_arrow(ctx, right_btn_x + H_SCROLLBAR_BUTTON_SIZE / 2.0f, sb_y + H_SCROLLBAR_HEIGHT / 2.0f, false);

        // Calculate thumb geometry
        float track_start = pane_x + H_SCROLLBAR_BUTTON_SIZE;
        float track_width = pane_width - 2 * H_SCROLLBAR_BUTTON_SIZE;
        if (track_width <= 0.0f) return;

        // Content area width for visible ratio calculation
        constexpr float LINE_NUM_WIDTH = DiffViewer::LINE_NUMBER_WIDTH;
        constexpr float BORDER_WIDTH = DiffViewer::LEFT_BORDER_WIDTH;
        constexpr float CONTENT_PAD = DiffViewer::CONTENT_PADDING;
        float content_area_width = pane_width - LINE_NUM_WIDTH - BORDER_WIDTH - CONTENT_PAD;
        float max_content = fmaxf(max_line_width_left, max_line_width_right);

        float visible_ratio = (max_content > 0.0f) ? (content_area_width / max_content) : 1.0f;
        float thumb_width = fmaxf(H_SCROLLBAR_MIN_THUMB, track_width * visible_ratio);

        float scroll_ratio = (max_scroll > 0.0f) ? (scroll_x / max_scroll) : 0.0f;
        scroll_ratio = fminf(1.0f, fmaxf(0.0f, scroll_ratio));  // Clamp to [0, 1]
        float thumb_left = track_start + scroll_ratio * (track_width - thumb_width);

        // Draw thumb
        D2D1_RECT_F thumb_rect = D2D1::RectF(
            thumb_left,
            sb_y + H_SCROLLBAR_THUMB_MARGIN,
            thumb_left + thumb_width,
            sb_y + H_SCROLLBAR_HEIGHT - H_SCROLLBAR_THUMB_MARGIN
        );
        uint32_t thumb_color = (hover == HScrollbarHover::Thumb || h_scrollbar_dragging)
                               ? Theme::TEXT_MUTED : Theme::BG_HOVER;
        ctx.fill_rounded_rect(thumb_rect, 3.0f, thumb_color);
    }

    void render(RenderContext& ctx) override {
        if (!(flags & WidgetFlags::Visible)) return;

        // In side-by-side mode, clip each pane separately for proper rendering
        if (view_mode == DiffViewMode::SideBySide) {
            constexpr float GUTTER_WIDTH = DiffViewer::CENTER_GUTTER_WIDTH;
            float available_for_panes = rect.width - GUTTER_WIDTH;
            float left_pane_width = available_for_panes * pane_split_ratio;
            float gutter_x = rect.x + left_pane_width;
            float right_pane_x = gutter_x + GUTTER_WIDTH;

            // Left pane clipping region (account for scrollbar at bottom)
            float pane_bottom = viewport_bottom - H_SCROLLBAR_HEIGHT;
            D2D1_RECT_F left_clip = D2D1::RectF(rect.x, viewport_top, gutter_x, pane_bottom);
            ctx.target->PushAxisAlignedClip(left_clip, D2D1_ANTIALIAS_MODE_PER_PRIMITIVE);
            for (size_t i = 0; i < active_count; i++) {
                if (active_widgets[i].pane_side == DiffPaneSide::Left) {
                    DiffLineWidget* widget = active_widgets[i].widget;
                    if (widget) {
                        widget->scroll_x_offset = scroll_x;  // Apply horizontal scroll
                        widget->render(ctx);
                    }
                }
            }
            ctx.target->PopAxisAlignedClip();

            // Right pane clipping region (account for scrollbar at bottom)
            D2D1_RECT_F right_clip = D2D1::RectF(right_pane_x, viewport_top, rect.x + rect.width, pane_bottom);
            ctx.target->PushAxisAlignedClip(right_clip, D2D1_ANTIALIAS_MODE_PER_PRIMITIVE);
            for (size_t i = 0; i < active_count; i++) {
                if (active_widgets[i].pane_side == DiffPaneSide::Right) {
                    DiffLineWidget* widget = active_widgets[i].widget;
                    if (widget) {
                        widget->scroll_x_offset = scroll_x;  // Apply horizontal scroll
                        widget->render(ctx);
                    }
                }
            }
            ctx.target->PopAxisAlignedClip();

            // Render horizontal scrollbars at bottom of each pane
            float sb_y = viewport_bottom - H_SCROLLBAR_HEIGHT;
            float right_pane_width = available_for_panes * (1.0f - pane_split_ratio);
            render_h_scrollbar(ctx, rect.x, left_pane_width, sb_y, true);   // Left pane
            render_h_scrollbar(ctx, right_pane_x, right_pane_width, sb_y, false);  // Right pane

            // Fill center gutter's scrollbar area (the gap between the two pane scrollbars)
            D2D1_RECT_F gutter_sb_area = D2D1::RectF(gutter_x, sb_y, gutter_x + GUTTER_WIDTH, viewport_bottom);
            ctx.fill_rect(gutter_sb_area, Theme::BG_SECONDARY);

            // Render center gutter
            if (center_gutter) {
                center_gutter->render(ctx);
            }
        } else {
            // Inline mode: render all active line widgets
            for (size_t i = 0; i < active_count; i++) {
                DiffLineWidget* widget = active_widgets[i].widget;
                if (!widget) continue;
                widget->render(ctx);
            }

            // Render center gutter in inline mode too
            if (center_gutter) {
                center_gutter->render(ctx);
            }
        }

        // Show placeholder if no diff, binary file, or no content
        bool has_content = (view_mode == DiffViewMode::SideBySide)
                          ? (sbs_index.pair_count > 0)
                          : (line_index.count > 0);
        if (!diff) {
            render_placeholder(ctx, L"Select a file to view diff");
        } else if (diff->is_binary) {
            render_placeholder(ctx, L"Binary file differs");
        } else if (!has_content) {
            render_placeholder(ctx, L"No changes in this file");
        }
    }

    void render_placeholder(RenderContext& ctx, const wchar_t* message) {
        // Center text in content area
        if (!g_text_format_body) return;

        // Create centered text layout
        IDWriteTextLayout* layout = nullptr;
        g_dwrite_factory->CreateTextLayout(
            message, static_cast<UINT32>(wcslen(message)),
            g_text_format_body, rect.width, 30.0f, &layout);

        if (layout) {
            layout->SetTextAlignment(DWRITE_TEXT_ALIGNMENT_CENTER);
            ctx.brush->SetColor(color_from_argb(Theme::TEXT_MUTED));
            D2D1_POINT_2F pt = D2D1::Point2F(rect.x, rect.y + 50.0f);
            ctx.target->DrawTextLayout(pt, layout, ctx.brush);
            layout->Release();
        }
    }

    // ========================================================================
    // Horizontal Scrollbar Interaction
    // ========================================================================

    // Scroll by small increment (column)
    void scroll_by_column_h(int direction) {
        constexpr float COLUMN_SCROLL = 40.0f;  // Pixels per column
        float pane_width = (rect.width - DiffViewer::CENTER_GUTTER_WIDTH) * pane_split_ratio;
        float max_scroll = calculate_max_scroll_x(pane_width);
        scroll_x += direction * COLUMN_SCROLL;
        scroll_x = fminf(fmaxf(0.0f, scroll_x), max_scroll);
        set_dirty();
    }

    // Scroll by large increment (page)
    void scroll_by_page_h(int direction) {
        constexpr float LINE_NUM_WIDTH = DiffViewer::LINE_NUMBER_WIDTH;
        constexpr float BORDER_WIDTH = DiffViewer::LEFT_BORDER_WIDTH;
        constexpr float CONTENT_PAD = DiffViewer::CONTENT_PADDING;

        float pane_width = (rect.width - DiffViewer::CENTER_GUTTER_WIDTH) * pane_split_ratio;
        float content_area_width = pane_width - LINE_NUM_WIDTH - BORDER_WIDTH - CONTENT_PAD;
        float max_scroll = calculate_max_scroll_x(pane_width);

        scroll_x += direction * (content_area_width * 0.9f);  // 90% of visible area
        scroll_x = fminf(fmaxf(0.0f, scroll_x), max_scroll);
        set_dirty();
    }

    // Check if point is in horizontal scrollbar area and which pane
    // Returns: 0=not in scrollbar, 1=left pane scrollbar, 2=right pane scrollbar
    int is_in_h_scrollbar_area(float local_x, float local_y) const {
        if (view_mode != DiffViewMode::SideBySide) return 0;

        // Check Y is in scrollbar range (bottom of viewport)
        float sb_y = viewport_bottom - rect.y - H_SCROLLBAR_HEIGHT;
        if (local_y < sb_y || local_y > sb_y + H_SCROLLBAR_HEIGHT) return 0;

        // Check X for left/right pane
        constexpr float GUTTER_WIDTH = DiffViewer::CENTER_GUTTER_WIDTH;
        float available_for_panes = rect.width - GUTTER_WIDTH;
        float left_pane_width = available_for_panes * pane_split_ratio;

        if (local_x >= 0 && local_x < left_pane_width) return 1;  // Left pane
        if (local_x >= left_pane_width + GUTTER_WIDTH) return 2;  // Right pane
        return 0;  // In gutter or outside
    }

    // Determine which part of the scrollbar is at the given position
    HScrollbarHover h_scrollbar_hit_test(float local_x, float pane_x, float pane_width) const {
        float rel_x = local_x - pane_x;  // Position relative to pane start

        // Left button
        if (rel_x < H_SCROLLBAR_BUTTON_SIZE) {
            return HScrollbarHover::LeftButton;
        }

        // Right button
        if (rel_x >= pane_width - H_SCROLLBAR_BUTTON_SIZE) {
            return HScrollbarHover::RightButton;
        }

        // Track area - check for thumb
        float track_start = H_SCROLLBAR_BUTTON_SIZE;
        float track_width = pane_width - 2 * H_SCROLLBAR_BUTTON_SIZE;
        if (track_width <= 0.0f) return HScrollbarHover::Track;

        float max_scroll = calculate_max_scroll_x(pane_width);
        if (max_scroll <= 0.0f) return HScrollbarHover::Track;

        // Calculate thumb position
        constexpr float LINE_NUM_WIDTH = DiffViewer::LINE_NUMBER_WIDTH;
        constexpr float BORDER_WIDTH = DiffViewer::LEFT_BORDER_WIDTH;
        constexpr float CONTENT_PAD = DiffViewer::CONTENT_PADDING;
        float content_area_width = pane_width - LINE_NUM_WIDTH - BORDER_WIDTH - CONTENT_PAD;
        float max_content = fmaxf(max_line_width_left, max_line_width_right);
        if (max_content <= 0.0f) return HScrollbarHover::Track;

        float visible_ratio = content_area_width / max_content;
        float thumb_width = fmaxf(H_SCROLLBAR_MIN_THUMB, track_width * visible_ratio);

        float scroll_ratio = scroll_x / max_scroll;
        float thumb_left = track_start + scroll_ratio * (track_width - thumb_width);
        float thumb_right = thumb_left + thumb_width;

        if (rel_x >= thumb_left && rel_x < thumb_right) {
            return HScrollbarHover::Thumb;
        }

        return HScrollbarHover::Track;
    }

    // ========================================================================
    // Mouse Event Handling - Forward to center gutter if in its bounds
    // ========================================================================

    // Check if point (in DiffViewerWidget-local coords) is in the gutter area
    bool is_in_gutter_area(float local_x, float local_y) const {
        (void)local_y;  // Y is not relevant for gutter hit test
        if (!center_gutter) return false;

        // Get gutter position relative to this widget's rect.x
        // Note: gutter.rect.x is absolute, rect.x is absolute
        float gutter_left = center_gutter->rect.x - rect.x;
        float gutter_right = gutter_left + center_gutter->rect.width;

        return local_x >= gutter_left && local_x <= gutter_right;
    }

    bool on_mouse_move(float x, float y) override {
        // Handle horizontal scrollbar drag first
        if (h_scrollbar_dragging) {
            float abs_x = rect.x + x;
            float delta_x = abs_x - h_drag_start_x;

            // Calculate how much scroll_x should change based on delta
            constexpr float GUTTER_WIDTH = DiffViewer::CENTER_GUTTER_WIDTH;
            float available_for_panes = rect.width - GUTTER_WIDTH;
            float pane_width = available_for_panes * pane_split_ratio;
            float track_width = pane_width - 2 * H_SCROLLBAR_BUTTON_SIZE;
            float max_scroll = calculate_max_scroll_x(pane_width);

            if (track_width > 0.0f && max_scroll > 0.0f) {
                // Calculate thumb width to get available track space
                constexpr float LINE_NUM_WIDTH = DiffViewer::LINE_NUMBER_WIDTH;
                constexpr float BORDER_WIDTH = DiffViewer::LEFT_BORDER_WIDTH;
                constexpr float CONTENT_PAD = DiffViewer::CONTENT_PADDING;
                float content_area_width = pane_width - LINE_NUM_WIDTH - BORDER_WIDTH - CONTENT_PAD;
                float max_content = fmaxf(max_line_width_left, max_line_width_right);
                if (max_content <= 0.0f) return true;  // No content to scroll

                float visible_ratio = content_area_width / max_content;
                float thumb_width = fmaxf(H_SCROLLBAR_MIN_THUMB, track_width * visible_ratio);
                float available_track = track_width - thumb_width;

                if (available_track > 0.0f) {
                    float scroll_delta = (delta_x / available_track) * max_scroll;
                    scroll_x = h_drag_start_scroll + scroll_delta;
                    scroll_x = fminf(fmaxf(0.0f, scroll_x), max_scroll);
                    set_dirty();
                }
            }
            return true;
        }

        // Update scrollbar hover states
        int sb_pane = is_in_h_scrollbar_area(x, y);
        HScrollbarHover old_hover_left = h_scrollbar_hover_left;
        HScrollbarHover old_hover_right = h_scrollbar_hover_right;

        if (sb_pane == 1) {
            // Hovering over left pane scrollbar
            constexpr float GUTTER_WIDTH = DiffViewer::CENTER_GUTTER_WIDTH;
            float available_for_panes = rect.width - GUTTER_WIDTH;
            float left_pane_width = available_for_panes * pane_split_ratio;
            h_scrollbar_hover_left = h_scrollbar_hit_test(x, 0.0f, left_pane_width);
            h_scrollbar_hover_right = HScrollbarHover::None;
        } else if (sb_pane == 2) {
            // Hovering over right pane scrollbar
            constexpr float GUTTER_WIDTH = DiffViewer::CENTER_GUTTER_WIDTH;
            float available_for_panes = rect.width - GUTTER_WIDTH;
            float left_pane_width = available_for_panes * pane_split_ratio;
            float right_pane_width = available_for_panes * (1.0f - pane_split_ratio);
            h_scrollbar_hover_right = h_scrollbar_hit_test(x, left_pane_width + GUTTER_WIDTH, right_pane_width);
            h_scrollbar_hover_left = HScrollbarHover::None;
        } else {
            h_scrollbar_hover_left = HScrollbarHover::None;
            h_scrollbar_hover_right = HScrollbarHover::None;
        }

        // Trigger redraw if hover state changed
        if (old_hover_left != h_scrollbar_hover_left || old_hover_right != h_scrollbar_hover_right) {
            set_dirty();
        }

        // Forward to center gutter if it exists and we're in side-by-side mode
        if (center_gutter && view_mode == DiffViewMode::SideBySide) {
            // Check if in gutter area or dragging
            if (center_gutter->is_dragging || is_in_gutter_area(x, y)) {
                // When dragging, pass ABSOLUTE coordinates (like EventDispatcher does for captured widgets)
                // This ensures stable drag even as the gutter moves
                if (center_gutter->is_dragging) {
                    float abs_x = rect.x + x;
                    float abs_y = rect.y + y;
                    return center_gutter->on_mouse_move(abs_x, abs_y);
                } else {
                    // When not dragging, pass gutter-local coordinates for hover detection
                    float gutter_local_x = x - (center_gutter->rect.x - rect.x);
                    float gutter_local_y = (rect.y + y) - center_gutter->rect.y;
                    return center_gutter->on_mouse_move(gutter_local_x, gutter_local_y);
                }
            } else {
                // Clear gutter hover state when mouse leaves
                center_gutter->on_mouse_leave();
            }
        }
        return false;
    }

    bool on_mouse_down(float x, float y, int button) override {
        // Right-click: show context menu
        if (button == 1 && on_context_menu) {
            // Calculate which line was clicked (simplified - just use y position)
            int clicked_line = -1;
            float content_y = y - HEADER_HEIGHT;
            if (content_y >= 0) {
                if (view_mode == DiffViewMode::Inline) {
                    clicked_line = static_cast<int>((scroll_y + content_y) / LINE_HEIGHT);
                    if (clicked_line >= static_cast<int>(line_index.count)) clicked_line = -1;
                } else {
                    // Side-by-side mode: calculate pair index
                    clicked_line = static_cast<int>((scroll_y + content_y) / LINE_HEIGHT);
                    if (clicked_line >= static_cast<int>(sbs_index.pair_count)) clicked_line = -1;
                }
            }
            // Convert to screen coordinates
            POINT pt = { static_cast<LONG>(rect.x + x), static_cast<LONG>(rect.y + y) };
            ClientToScreen(g_main_window, &pt);
            on_context_menu(this, clicked_line, static_cast<float>(pt.x), static_cast<float>(pt.y), context_menu_user_data);
            return true;
        }

        // Check horizontal scrollbar first
        int sb_pane = is_in_h_scrollbar_area(x, y);
        if (sb_pane > 0 && button == 0) {  // Left click on scrollbar
            constexpr float GUTTER_WIDTH = DiffViewer::CENTER_GUTTER_WIDTH;
            float available_for_panes = rect.width - GUTTER_WIDTH;
            float left_pane_width = available_for_panes * pane_split_ratio;
            float right_pane_width = available_for_panes * (1.0f - pane_split_ratio);

            float pane_x = (sb_pane == 1) ? 0.0f : (left_pane_width + GUTTER_WIDTH);
            float pane_width = (sb_pane == 1) ? left_pane_width : right_pane_width;

            HScrollbarHover hit = h_scrollbar_hit_test(x, pane_x, pane_width);

            switch (hit) {
                case HScrollbarHover::LeftButton:
                    scroll_by_column_h(-1);
                    return true;
                case HScrollbarHover::RightButton:
                    scroll_by_column_h(1);
                    return true;
                case HScrollbarHover::Thumb:
                    h_scrollbar_dragging = true;
                    h_drag_start_x = rect.x + x;  // Store absolute position
                    h_drag_start_scroll = scroll_x;
                    return true;
                case HScrollbarHover::Track: {
                    // Page scroll based on click position relative to thumb
                    float rel_x = x - pane_x;
                    float track_start = H_SCROLLBAR_BUTTON_SIZE;
                    float track_width = pane_width - 2 * H_SCROLLBAR_BUTTON_SIZE;
                    float max_scroll = calculate_max_scroll_x(pane_width);

                    if (max_scroll > 0.0f && track_width > 0.0f) {
                        // Calculate thumb position to determine scroll direction
                        constexpr float LINE_NUM_WIDTH = DiffViewer::LINE_NUMBER_WIDTH;
                        constexpr float BORDER_WIDTH = DiffViewer::LEFT_BORDER_WIDTH;
                        constexpr float CONTENT_PAD = DiffViewer::CONTENT_PADDING;
                        float content_area_width = pane_width - LINE_NUM_WIDTH - BORDER_WIDTH - CONTENT_PAD;
                        float max_content = fmaxf(max_line_width_left, max_line_width_right);
                        if (max_content > 0.0f) {
                            float visible_ratio = content_area_width / max_content;
                            float thumb_width = fmaxf(H_SCROLLBAR_MIN_THUMB, track_width * visible_ratio);
                            float scroll_ratio = scroll_x / max_scroll;
                            float thumb_center = track_start + scroll_ratio * (track_width - thumb_width) + thumb_width / 2.0f;

                            scroll_by_page_h((rel_x < thumb_center) ? -1 : 1);
                        }
                    }
                    return true;
                }
                default:
                    break;
            }
        }

        // Then check center gutter
        if (center_gutter && view_mode == DiffViewMode::SideBySide) {
            if (is_in_gutter_area(x, y)) {
                // Pass gutter-local coordinates for initial click
                float gutter_local_x = x - (center_gutter->rect.x - rect.x);
                float gutter_local_y = (rect.y + y) - center_gutter->rect.y;
                return center_gutter->on_mouse_down(gutter_local_x, gutter_local_y, button);
            }
        }
        return false;
    }

    bool on_mouse_up(float x, float y, int button) override {
        // Release horizontal scrollbar drag
        if (h_scrollbar_dragging && button == 0) {
            h_scrollbar_dragging = false;
            return true;
        }

        if (center_gutter && view_mode == DiffViewMode::SideBySide) {
            // Always forward if dragging, otherwise only if in gutter area
            if (center_gutter->is_dragging || is_in_gutter_area(x, y)) {
                // When dragging, pass absolute coordinates
                if (center_gutter->is_dragging) {
                    float abs_x = rect.x + x;
                    float abs_y = rect.y + y;
                    return center_gutter->on_mouse_up(abs_x, abs_y, button);
                } else {
                    float gutter_local_x = x - (center_gutter->rect.x - rect.x);
                    float gutter_local_y = (rect.y + y) - center_gutter->rect.y;
                    return center_gutter->on_mouse_up(gutter_local_x, gutter_local_y, button);
                }
            }
        }
        return false;
    }

    bool on_mouse_leave() override {
        // Clear scrollbar hover states
        if (h_scrollbar_hover_left != HScrollbarHover::None ||
            h_scrollbar_hover_right != HScrollbarHover::None) {
            h_scrollbar_hover_left = HScrollbarHover::None;
            h_scrollbar_hover_right = HScrollbarHover::None;
            set_dirty();
        }

        if (center_gutter) {
            center_gutter->on_mouse_leave();
        }
        return false;
    }
};

// ============================================================================
// DiffHeaderWidget method implementations (after DiffViewerWidget is defined)
// ============================================================================

void DiffHeaderWidget::set_diff(const FileDiff* diff) {
    if (diff) {
        int result = MultiByteToWideChar(CP_UTF8, 0, diff->path, -1, header_path, Git::MAX_PATH_LEN);
        if (result == 0) header_path[0] = L'\0';
        additions = diff->additions;
        deletions = diff->deletions;

        // Determine if we should show nav based on diff type
        if (diff->is_new_file || diff->is_deleted) {
            hunk_count = 0;
        }
        // hunk_count will be updated via update_hunk_display from content widget
    } else {
        header_path[0] = L'\0';
        additions = 0;
        deletions = 0;
        hunk_count = 0;
    }
    current_hunk = 0;
    set_dirty();
}

void DiffHeaderWidget::navigate_prev_hunk() {
    if (content) {
        content->navigate_prev_hunk();
    }
}

void DiffHeaderWidget::navigate_next_hunk() {
    if (content) {
        content->navigate_next_hunk();
    }
}

void DiffHeaderWidget::toggle_view_mode() {
    if (!content) return;

    // Toggle between modes
    DiffViewMode new_mode = (view_mode == DiffViewMode::SideBySide)
                           ? DiffViewMode::Inline
                           : DiffViewMode::SideBySide;

    // Update content widget
    content->set_view_mode(new_mode);

    // Update our state
    view_mode = new_mode;
    set_dirty();

    // Persist preference to settings
    g_app_settings.diff_side_by_side = (new_mode == DiffViewMode::SideBySide);
    settings_save_app_settings(&g_app_settings);
}

// ============================================================================
// Test Framework - Press F12 to show test dialog
// ============================================================================

static WidgetTree g_test_tree = {};
static Dialog* g_test_dialog = nullptr;
static int g_test_click_count = 0;

static void test_button_clicked(Button* btn, void* user_data) {
    (void)btn; (void)user_data;
    g_test_click_count++;
    LOG("Test button clicked! Count: %d", g_test_click_count);

    // Update the label to show click count
    if (g_test_dialog && g_test_dialog->content) {
        // Find the label (first child of content)
        Widget* content = g_test_dialog->content;
        for (Widget* child = content->first_child; child; child = child->next_sibling) {
            Label* lbl = dynamic_cast<Label*>(child);
            if (lbl) {
                static wchar_t count_text[64];
                swprintf_s(count_text, L"Button clicked %d times!", g_test_click_count);
                lbl->text = count_text;
                lbl->set_dirty();
                break;
            }
        }
    }
}

static void test_dialog_closed(Dialog* dlg, void* user_data) {
    (void)dlg; (void)user_data;
    LOG("Test dialog closed");
    g_event_dispatcher.root = nullptr;
}

static void test_checkbox_changed(Checkbox* cb, bool checked, void* user_data) {
    (void)cb; (void)user_data;
    LOG("Checkbox changed: %s", checked ? "checked" : "unchecked");
}

static void test_input_changed(TextInput* input, void* user_data) {
    (void)user_data;
    char text_utf8[256];
    WideCharToMultiByte(CP_UTF8, 0, input->text, -1, text_utf8, sizeof(text_utf8), nullptr, nullptr);
    LOG("Input changed: %s", text_utf8);
}

static void ui_framework_test_init() {
    if (g_test_dialog) return;  // Already initialized

    LOG("Initializing UI framework test dialog...");

    // Create dialog
    g_test_dialog = g_widget_arena.create<Dialog>();
    g_test_dialog->title = L"UI Framework Test";
    g_test_dialog->dialog_width = 400.0f;
    g_test_dialog->dialog_height = 300.0f;
    g_test_dialog->on_close = test_dialog_closed;

    // Create content container (FlexContainer with column layout)
    FlexContainer* content = g_widget_arena.create<FlexContainer>();
    content->direction = FlexDirection::Column;
    content->gap = 12.0f;
    content->padding_top = 8.0f;

    // Add a label
    Label* label = g_widget_arena.create<Label>();
    label->text = L"Welcome to the UI Framework test!";
    label->color = Theme::TEXT_PRIMARY;
    label->preferred_height = 24.0f;
    widget_add_child(content, label);

    // Add a text input
    TextInput* input = g_widget_arena.create<TextInput>();
    input->placeholder = L"Type something here...";
    input->preferred_width = 300.0f;
    input->on_change = test_input_changed;
    widget_add_child(content, input);

    // Add a checkbox
    Checkbox* checkbox = g_widget_arena.create<Checkbox>();
    checkbox->label = L"Enable awesome mode";
    checkbox->on_change = test_checkbox_changed;
    widget_add_child(content, checkbox);

    // Add a button row
    FlexContainer* button_row = g_widget_arena.create<FlexContainer>();
    button_row->direction = FlexDirection::Row;
    button_row->gap = 8.0f;
    button_row->justify = FlexJustify::End;
    button_row->preferred_height = 40.0f;

    Button* btn = g_widget_arena.create<Button>();
    btn->text = L"Click Me!";
    btn->on_click = test_button_clicked;
    btn->preferred_width = 100.0f;
    btn->preferred_height = 36.0f;
    widget_add_child(button_row, btn);

    Button* close_btn = g_widget_arena.create<Button>();
    close_btn->text = L"Close";
    close_btn->bg_normal = BranchDialog::BUTTON_SECONDARY;
    close_btn->bg_hover = BranchDialog::BUTTON_SECONDARY_HOVER;
    close_btn->bg_pressed = Theme::BG_TERTIARY;
    close_btn->on_click = [](Button* b, void* ud) {
        (void)b; (void)ud;
        if (g_test_dialog) g_test_dialog->close();
    };
    close_btn->preferred_width = 80.0f;
    close_btn->preferred_height = 36.0f;
    widget_add_child(button_row, close_btn);

    widget_add_child(content, button_row);

    // Set content on dialog
    g_test_dialog->set_content(content);

    // Set up tree
    g_test_tree.root = g_test_dialog;

    LOG("Test dialog initialized");
}

static void ui_framework_test_show() {
    ui_framework_test_init();

    if (g_test_dialog) {
        g_test_dialog->show();
        g_event_dispatcher.root = g_test_dialog;

        // Measure and layout
        LayoutConstraints constraints;
        if (g_render_target) {
            D2D1_SIZE_F size = g_render_target->GetSize();
            constraints.max_width = size.width;
            constraints.max_height = size.height;
        } else {
            constraints.max_width = 1280.0f;
            constraints.max_height = 720.0f;
        }

        LayoutEngine::measure_tree(g_test_dialog, constraints);
        g_test_dialog->rect.x = 0;
        g_test_dialog->rect.y = 0;
        g_test_dialog->rect.width = constraints.max_width;
        g_test_dialog->rect.height = constraints.max_height;
        LayoutEngine::layout_tree(g_test_dialog);

        LOG("Test dialog shown");
    }
}

static void ui_framework_test_toggle() {
    if (g_test_dialog && g_test_dialog->visible) {
        g_test_dialog->close();
    } else {
        ui_framework_test_show();
    }
}

static void ui_framework_test_render() {
    if (!g_test_dialog || !g_test_dialog->visible || !g_render_target) return;

    g_test_tree.render(g_render_target);
}
